import { Info } from 'lucide-react';

import React from 'react';
import { File, Folder, ChevronRight, ChevronDown, CheckSquare, Square, Search } from 'lucide-react';

interface FileNode {
  name: string;
  kind: 'file' | 'directory';
  handle: FileSystemHandle;
  children?: FileNode[];
  path: string;
}

interface Props {
  files: FileNode[];
  selectedPaths: Set<string>;
  onToggleSelection: (path: string) => void;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
}

export const FileBrowser: React.FC<Props> = ({ files, selectedPaths, onToggleSelection, searchTerm, setSearchTerm }) => {
  const [expandedFolders, setExpandedFolders] = React.useState<Set<string>>(new Set());

  const toggleFolder = (path: string) => {
    const next = new Set(expandedFolders);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setExpandedFolders(next);
  };

  const renderNode = (node: FileNode, depth: number = 0) => {
    const isExpanded = expandedFolders.has(node.path);
    const isSelected = selectedPaths.has(node.path);
    const isDirectory = node.kind === 'directory';

    // Simple search filtering
    if (searchTerm && !node.path.toLowerCase().includes(searchTerm.toLowerCase())) {
      return null;
    }

    return (
      <div key={node.path} className="select-none">
        <div 
          className={`flex items-center py-1.5 px-2 hover:bg-slate-800 rounded-lg cursor-pointer transition-colors group ${isSelected ? 'bg-indigo-500/10' : ''}`}
          style={{ paddingLeft: `${depth * 1.25 + 0.5}rem` }}
        >
          <div 
            className="mr-2 text-slate-500 hover:text-slate-300 transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              if (isDirectory) toggleFolder(node.path);
            }}
          >
            {isDirectory ? (
              isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />
            ) : (
              <div className="w-4" />
            )}
          </div>

          <div 
            className="flex items-center flex-1"
            onClick={() => isDirectory ? toggleFolder(node.path) : onToggleSelection(node.path)}
          >
            {isDirectory ? (
              <Folder className="w-4 h-4 mr-2 text-indigo-400 fill-indigo-400/20" />
            ) : (
              <File className="w-4 h-4 mr-2 text-slate-400" />
            )}
            <span className={`text-sm ${isSelected ? 'text-indigo-300 font-medium' : 'text-slate-300'}`}>
              {node.name}
            </span>
          </div>

          {!isDirectory && (
            <div 
              className="ml-auto"
              onClick={(e) => {
                e.stopPropagation();
                onToggleSelection(node.path);
              }}
            >
              {isSelected ? (
                <CheckSquare className="w-4 h-4 text-indigo-500" />
              ) : (
                <Square className="w-4 h-4 text-slate-600 group-hover:text-slate-400" />
              )}
            </div>
          )}
        </div>

        {isDirectory && isExpanded && node.children && (
          <div className="mt-0.5">
            {node.children.map(child => renderNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 border border-slate-800 rounded-xl overflow-hidden">
      <div className="p-3 border-b border-slate-800 bg-slate-900">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input 
            type="text"
            placeholder="Search system logs..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-950 border border-slate-800 rounded-lg py-1.5 pl-9 pr-3 text-xs text-slate-300 focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-2 scrollbar-thin scrollbar-thumb-slate-700">
        {files.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 text-xs italic p-4 text-center">
            No files discovered. Ensure permissions are granted.
          </div>
        ) : (
          files.map(node => renderNode(node))
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { 
  ShieldCheck, 
