import { FileBrowser } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity } from './types';
import { analyzeAgentLogs } from './services/geminiService';

interface FileNode {
  name: string;
  kind: 'file' | 'directory';
  handle: FileSystemHandle;
  children?: FileNode[];
  path: string;
}

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = ''): Promise<FileNode[]> => {
    const nodes: FileNode[] = [];
    try {
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind,
          handle: entry,
          path: currentPath
        };

        if (entry.kind === 'directory') {
          node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath);
        }
        nodes.push(node);
      }
    } catch (e) {
      console.error("Error scanning subdirectory", e);
    }
    return nodes.sort((a, b) => {
      if (a.kind !== b.kind) return a.kind === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  };

  const handleMountDirectory = async () => {
    setIsMounting(true);
    addNotification("Opening system file picker...", "info");

    try {
      // Check if API is supported
      if (!('showDirectoryPicker' in window)) {
        throw new Error("Your browser does not support the File System Access API. Please use a modern desktop browser like Chrome or Edge.");
      }

      // @ts-ignore - File System Access API
      const handle = await window.showDirectoryPicker({
        mode: 'readwrite'
      });

      setDirectoryHandle(handle);
      addNotification(`Access granted to ${handle.name}. Indexing files...`, "success");

      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
      addNotification("System indexing complete.", "success");
    } catch (err: any) {
      console.error("Directory access denied or failed:", err);
      if (err.name === 'AbortError') {
        addNotification("System access request cancelled.", "info");
      } else {
        addNotification(err.message || "Failed to mount directory. Please try again.", "error");
      }
    } finally {
      setIsMounting(false);
    }
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("File deselected.", "info");
    } else {
      next.add(path);
      addNotification("File added to scan scope.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification(`Starting Deep Scan on ${selectedPaths.size} files...`, "info");

    let combinedLogs = logInput;

    if (selectedPaths.size > 0 && directoryHandle) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            const file = await (node.handle as FileSystemFileHandle).getFile();
            const text = await file.text();
            fileContents.push(`--- FILE: ${path} ---\n${text}`);
          }
        }
        combinedLogs = `${combinedLogs}\n\n${fileContents.join('\n\n')}`;
      } catch (err: any) {
        addNotification("Failed to read one or more files. Check permissions.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No log data provided for analysis.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Deep scan analysis complete.", "success");
    } catch (err) {
      console.error(err);
      addNotification("Analysis failed. The model might be overloaded or the logs are too large.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    addNotification("Dashboard reset. Ready for new session.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-8">
              <div className="inline-flex p-4 rounded-2xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20">
                <BrainCircuit className="w-10 h-10" />
              </div>
              <h2 className="text-3xl font-extrabold text-white mb-4 tracking-tight">Agent Sentinel Integrity Scan</h2>
              <p className="text-slate-400 text-lg max-w-2xl mx-auto">
                Comprehensive alignment auditing. Mount your system logs directory for a deep, 
                multi-file cross-referencing analysis of agent behavior.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              {/* File System Browser Column */}
              <div className="lg:col-span-5 flex flex-col space-y-4">
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl flex-1 flex flex-col">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-2">
                      <FolderOpen className="w-5 h-5 text-indigo-400" />
                      <h3 className="text-sm font-bold text-white uppercase tracking-wider">Mounted System</h3>
                    </div>
                    {directoryHandle ? (
                      <div className="flex items-center space-x-1 px-2 py-1 bg-emerald-500/10 border border-emerald-500/20 rounded-md">
                        <Unlock className="w-3 h-3 text-emerald-400" />
                        <span className="text-[10px] font-bold text-emerald-400 uppercase">ACCESS GRANTED</span>
                      </div>
                    ) : (
                      <div className="flex items-center space-x-1 px-2 py-1 bg-slate-800 border border-slate-700 rounded-md">
                        <Lock className="w-3 h-3 text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-500 uppercase">RESTRICTED</span>
                      </div>
                    )}
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-xl p-8 text-center bg-slate-950/50 min-h-[400px]">
                      <div className="p-4 bg-slate-900 rounded-full mb-4">
                        {isMounting ? (
                          <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" />
                        ) : (
                          <Settings className="w-8 h-8 text-slate-600" />
                        )}
                      </div>
                      <h4 className="text-white font-semibold mb-2">
                        {isMounting ? "Requesting Permissions..." : "Initialize System Scan"}
                      </h4>
                      <p className="text-xs text-slate-500 mb-6 max-w-[200px]">
                        Grant Sentinel permission to read your agent log directory for holistic analysis.
                      </p>
                      <button 
                        onClick={handleMountDirectory}
                        disabled={isMounting}
                        className={`px-6 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-bold rounded-lg border border-slate-700 transition-all flex items-center shadow-lg active:scale-95 disabled:opacity-50`}
                      >
                        {isMounting ? 'Waiting for Dialog...' : 'Grant System Access'}
                      </button>
                    </div>
                  ) : (
                    <div className="flex-1 overflow-hidden flex flex-col">
                      <div className="flex-1 min-h-[400px]">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                        />
                      </div>
                      <div className="mt-4 flex items-center justify-between text-[10px] text-slate-500 font-bold uppercase tracking-widest px-2">
                        <span>Selected: {selectedPaths.size} Files</span>
                        <button 
                          onClick={() => {
                            setSelectedPaths(new Set());
                            addNotification("Selection cleared.", "info");
                          }} 
                          className="hover:text-indigo-400 transition-colors"
                        >
                          Clear Selection
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Manual Input & Start Action Column */}
              <div className="lg:col-span-7 space-y-4 flex flex-col">
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl flex-1 flex flex-col">
                  <div className="flex items-center space-x-2 mb-4">
                    <Terminal className="w-5 h-5 text-indigo-400" />
                    <h3 className="text-sm font-bold text-white uppercase tracking-wider">Context Overrides / Notes</h3>
                  </div>
                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Paste specific log snippets or instructions for the deep scan..."
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-xl p-4 text-slate-300 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all code-font text-sm mb-6 placeholder:text-slate-700 min-h-[200px]"
                  />

                  <div className="p-4 bg-indigo-500/5 border border-indigo-500/20 rounded-xl mb-6">
                    <div className="flex items-start space-x-3">
                      <Eye className="w-5 h-5 text-indigo-400 shrink-0 mt-0.5" />
                      <div>
                        <h4 className="text-sm font-bold text-indigo-300">Holistic Visibility Enabled</h4>
                        <p className="text-xs text-slate-400 leading-relaxed mt-1">
                          Sentinel will analyze all selected files from the system alongside your manual input to find patterns of misalignment across different execution threads.
                        </p>
                      </div>
                    </div>
                  </div>

                  <button
                    onClick={handleDeepScan}
                    disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)}
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl transition-all flex items-center justify-center shadow-lg shadow-indigo-600/20 text-lg active:scale-[0.98]"
                  >
                    {isAnalyzing ? (
                      <>
                        <Activity className="w-6 h-6 mr-3 animate-spin" />
                        Scanning System Integrity...
                      </>
                    ) : (
                      <>
                        <Zap className="w-6 h-6 mr-3 fill-white" />
                        Execute Deep Scan
                        <ChevronRight className="w-6 h-6 ml-2" />
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>

            <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <Target className="w-6 h-6 text-indigo-400 mb-4" />
                <h3 className="text-white font-semibold mb-2">Cross-Reference Search</h3>
                <p className="text-sm text-slate-400">Scan multiple files simultaneously to find drift across different sessions.</p>
              </div>
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <Lock className="w-6 h-6 text-amber-400 mb-4" />
                <h3 className="text-white font-semibold mb-2">Privacy Sandbox</h3>
                <p className="text-sm text-slate-400">Temporary file handles are used; your log data is only accessed during scanning.</p>
              </div>
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <Activity className="w-6 h-6 text-emerald-400 mb-4" />
                <h3 className="text-white font-semibold mb-2">Live Monitoring</h3>
                <p className="text-sm text-slate-400">Identify emergent misalignment in real-time as logs are written to disk.</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard 
                title="Alignment Score" 
                value={`${data?.stats.alignmentScore}%`} 
                icon={Target} 
                color="bg-indigo-500" 
                subtext="System Integrity Rating"
              />
              <StatCard 
                title="Total Anomalies" 
                value={data?.stats.anomalyCount || 0} 
                icon={AlertOctagon} 
                color="bg-rose-500" 
                subtext="Detected in deep scan"
              />
              <StatCard 
                title="Critical Risks" 
                value={data?.stats.criticalRisks || 0} 
                icon={ShieldCheck} 
                color="bg-amber-500" 
                subtext="Immediate action items"
              />
              <StatCard 
                title="Scanned Files" 
                value={selectedPaths.size || 1} 
                icon={FolderOpen} 
                color="bg-emerald-500" 
