                  <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={data?.riskTrend}>
                        <defs>
                          <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <XAxis dataKey="time" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                        <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                        <Tooltip 
                          contentStyle={{ backgroundColor: '#0f172a', borderColor: '#1e293b', borderRadius: '8px' }}
                          itemStyle={{ color: '#6366f1' }}
                        />
                        <Area 
                          type="monotone" 
                          dataKey="score" 
                          stroke="#6366f1" 
                          fillOpacity={1} 
                          fill="url(#colorScore)" 
                          strokeWidth={3}
                        />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                    <MessageSquare className="w-5 h-5 mr-2 text-indigo-400" />
                    Comprehensive System Report
                  </h3>
                  <div className="prose prose-invert max-w-none">
                    <p className="text-slate-300 leading-relaxed bg-slate-950 p-4 rounded-xl border border-slate-800 italic">
                      {data?.summary}
                    </p>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg font-bold text-white flex items-center">
                    <AlertOctagon className="w-5 h-5 mr-2 text-rose-400" />
                    Anomaly Feed
                  </h3>
                </div>

                <div className="space-y-1">
                  {data?.anomalies.map((anomaly) => (
                    <AnomalyItem key={anomaly.id} anomaly={anomaly} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 px-4 py-2 bg-slate-900/80 backdrop-blur-md border border-slate-700 rounded-full flex items-center space-x-4 shadow-2xl z-50">
        <div className="flex -space-x-2">
          {[1, 2, 3].map(i => (
            <img key={i} src={`https://picsum.photos/seed/${i + 20}/32/32`} className="w-6 h-6 rounded-full border-2 border-slate-900" alt="Analyst" />
          ))}
        </div>
        <span className="text-[10px] font-medium text-slate-400">Agent Sentinel v2.5.1 • Feedback Engine Active</span>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';
import { File, Folder, ChevronRight, ChevronDown, CheckSquare, Square, Search, FileJson, FileText, MessageSquareQuote } from 'lucide-react';

export interface FileNode {
  name: string;
  kind: 'file' | 'directory';
  handle: FileSystemHandle;
  children?: FileNode[];
  path: string;
}

interface Props {
  files: FileNode[];
  selectedPaths: Set<string>;
  onToggleSelection: (path: string) => void;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  targetPath?: string; // New: allow external control to jump to path
}

export const FileBrowser: React.FC<Props> = ({ files, selectedPaths, onToggleSelection, searchTerm, setSearchTerm, targetPath }) => {
  const [expandedFolders, setExpandedFolders] = React.useState<Set<string>>(new Set());

  // Auto-expand folders when a target path is provided
  useEffect(() => {
    if (targetPath) {
      const parts = targetPath.split('/');
      const newExpanded = new Set(expandedFolders);
      let current = '';
      parts.forEach(part => {
        current = current ? `${current}/${part}` : part;
        newExpanded.add(current);
      });
      setExpandedFolders(newExpanded);
    }
  }, [targetPath]);

  const toggleFolder = (path: string) => {
    const next = new Set(expandedFolders);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setExpandedFolders(next);
  };

  const getFileIcon = (name: string, isDirectory: boolean) => {
    if (isDirectory) return <Folder className="w-4 h-4 mr-2 text-indigo-400 fill-indigo-400/20" />;
    const ext = name.split('.').pop()?.toLowerCase();
    if (ext === 'json') return <FileJson className="w-4 h-4 mr-2 text-amber-400" />;
    if (ext === 'log' || ext === 'txt') return <FileText className="w-4 h-4 mr-2 text-slate-400" />;
    if (name.includes('chat') || name.includes('conversation')) return <MessageSquareQuote className="w-4 h-4 mr-2 text-emerald-400" />;
    return <File className="w-4 h-4 mr-2 text-slate-500" />;
  };

  const renderNode = (node: FileNode, depth: number = 0) => {
    const isExpanded = expandedFolders.has(node.path);
    const isSelected = selectedPaths.has(node.path);
    const isDirectory = node.kind === 'directory';
    const isTarget = targetPath === node.path;

    // Simple search filtering
    if (searchTerm && !node.path.toLowerCase().includes(searchTerm.toLowerCase())) {
      return null;
    }

    return (
      <div key={node.path} className="select-none">
        <div 
          className={`flex items-center py-1.5 px-2 hover:bg-slate-800 rounded-lg cursor-pointer transition-all group ${isSelected ? 'bg-indigo-500/10' : ''} ${isTarget ? 'ring-1 ring-indigo-500 bg-indigo-500/5' : ''}`}
          style={{ paddingLeft: `${depth * 1.25 + 0.5}rem` }}
        >
          <div 
            className="mr-2 text-slate-500 hover:text-slate-300 transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              if (isDirectory) toggleFolder(node.path);
            }}
          >
            {isDirectory ? (
              isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />
            ) : (
              <div className="w-4" />
            )}
          </div>

          <div 
            className="flex items-center flex-1"
            onClick={() => isDirectory ? toggleFolder(node.path) : onToggleSelection(node.path)}
          >
            {getFileIcon(node.name, isDirectory)}
            <span className={`text-sm ${isSelected ? 'text-indigo-300 font-medium' : 'text-slate-300'}`}>
              {node.name}
            </span>
          </div>

          {!isDirectory && (
            <div 
              className="ml-auto"
              onClick={(e) => {
                e.stopPropagation();
                onToggleSelection(node.path);
              }}
            >
              {isSelected ? (
                <CheckSquare className="w-4 h-4 text-indigo-500" />
              ) : (
                <Square className="w-4 h-4 text-slate-600 group-hover:text-slate-400" />
              )}
            </div>
          )}
        </div>

        {isDirectory && isExpanded && node.children && (
          <div className="mt-0.5">
            {node.children.map(child => renderNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 border border-slate-800 rounded-xl overflow-hidden">
      <div className="p-3 border-b border-slate-800 bg-slate-900">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input 
            type="text"
            placeholder="Search filenames or extensions..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-950 border border-slate-800 rounded-lg py-1.5 pl-9 pr-3 text-xs text-slate-300 focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-2 scrollbar-thin scrollbar-thumb-slate-700 max-h-[500px]">
        {files.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 text-xs italic p-12 text-center">
            No files indexed.
          </div>
        ) : (
          files.map(node => renderNode(node))
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  BarChart3, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
  FolderOpen,
  Lock,
  Unlock,
  Eye,
  Settings,
  Info,
  Loader2,
  Navigation,
  FileCode,
  ArrowRight
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
import { AnomalyItem } from './components/AnomalyItem';
import { FileBrowser, FileNode } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity } from './types';
import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jumpPath, setJumpPath] = useState('');
  const [activeJumpPath, setActiveJumpPath] = useState<string | undefined>(undefined);

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = ''): Promise<FileNode[]> => {
    const nodes: FileNode[] = [];
    try {
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind,
          handle: entry,
          path: currentPath
        };

        if (entry.kind === 'directory') {
          node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath);
        }
        nodes.push(node);
      }
    } catch (e) {
      console.error("Error scanning subdirectory", e);
    }
    return nodes.sort((a, b) => {
      if (a.kind !== b.kind) return a.kind === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  };

  const handleMountDirectory = async () => {
    setIsMounting(true);
    addNotification("Opening system file picker...", "info");

    try {
      if (!('showDirectoryPicker' in window)) {
        throw new Error("Your browser does not support File System Access API.");
      }

      // @ts-ignore
      const handle = await window.showDirectoryPicker({ mode: 'read' });

      setDirectoryHandle(handle);
      addNotification(`Access granted to ${handle.name}.`, "success");

      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
      addNotification("File tree indexing complete.", "success");
    } catch (err: any) {
      if (err.name === 'AbortError') {
        addNotification("System access cancelled.", "info");
      } else {
        addNotification(err.message || "Failed to mount directory.", "error");
      }
    } finally {
      setIsMounting(false);
    }
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const handleJumpToPath = () => {
    if (!jumpPath.trim()) return;
    const node = findNodeByPath(fileTree, jumpPath.trim());
    if (node) {
      setActiveJumpPath(node.path);
      addNotification(`Navigated to: ${node.path}`, "success");
    } else {
      addNotification("Path not found in mounted system.", "error");
    }
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("File removed from scan scope.", "info");
    } else {
      next.add(path);
      addNotification("File added for interpretation.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification(`Retrieving data from ${selectedPaths.size} sources...`, "info");

    let combinedLogs = logInput;

    if (selectedPaths.size > 0 && directoryHandle) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            const file = await (node.handle as FileSystemFileHandle).getFile();
            const text = await file.text();
            fileContents.push(`--- FILE [${path}] ---\n${text}`);
          }
        }
        combinedLogs = `${combinedLogs}\n\n${fileContents.join('\n\n')}`;
      } catch (err: any) {
        addNotification("Error reading file contents.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No data provided for analysis.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Integrity analysis finished.", "success");
    } catch (err) {
      console.error(err);
      addNotification("Deep scan failed. Try a smaller set of files.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    addNotification("Scanner reset.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-8">
              <div className="inline-flex p-4 rounded-2xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-lg shadow-indigo-500/10">
                <BrainCircuit className="w-10 h-10" />
              </div>
              <h2 className="text-3xl font-extrabold text-white mb-4 tracking-tight">Agent Sentinel Integrity Scan</h2>
              <p className="text-slate-400 text-lg max-w-2xl mx-auto">
                Advanced retrieval and interpretation tool for auditing agent logs, 
                chat histories, and system schemas.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              {/* File Retrieval Column */}
              <div className="lg:col-span-5 flex flex-col space-y-4">
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl flex-1 flex flex-col overflow-hidden">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-2">
                      <FolderOpen className="w-5 h-5 text-indigo-400" />
                      <h3 className="text-sm font-bold text-white uppercase tracking-wider">Retrieval Engine</h3>
                    </div>
                    {directoryHandle ? (
                      <div className="flex items-center space-x-1 px-2 py-1 bg-emerald-500/10 border border-emerald-500/20 rounded-md">
                        <Unlock className="w-3 h-3 text-emerald-400" />
                        <span className="text-[10px] font-bold text-emerald-400 uppercase">ACTIVE</span>
                      </div>
                    ) : (
                      <div className="flex items-center space-x-1 px-2 py-1 bg-slate-800 border border-slate-700 rounded-md">
                        <Lock className="w-3 h-3 text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-500 uppercase">OFFLINE</span>
                      </div>
                    )}
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-xl p-8 text-center bg-slate-950/50 min-h-[400px]">
                      <div className="p-4 bg-slate-900 rounded-full mb-4">
                        {isMounting ? <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" /> : <Settings className="w-8 h-8 text-slate-600" />}
                      </div>
                      <h4 className="text-white font-semibold mb-2">{isMounting ? "Granting Access..." : "Select Root Directory"}</h4>
                      <p className="text-xs text-slate-500 mb-6 max-w-[200px]">Mount your system storage to browse and audit specific paths.</p>
                      <button 
                        onClick={handleMountDirectory}
                        className="px-6 py-2 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs font-bold rounded-lg border border-slate-700 transition-all flex items-center shadow-lg active:scale-95"
                      >
                        Grant System Access
                      </button>
                    </div>
                  ) : (
                    <div className="flex-1 overflow-hidden flex flex-col space-y-3">
                      {/* Path Jump Bar */}
                      <div className="flex items-center space-x-2">
                        <div className="relative flex-1">
                          <Navigation className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-500" />
                          <input 
                            type="text"
                            placeholder="Jump to path (e.g. project/logs)..."
                            value={jumpPath}
                            onChange={(e) => setJumpPath(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleJumpToPath()}
                            className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 pl-9 pr-3 text-xs text-slate-300 focus:outline-none focus:ring-1 focus:ring-indigo-500"
                          />
                        </div>
                        <button 
                          onClick={handleJumpToPath}
                          className="p-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg transition-colors"
                          title="Navigate to Path"
                        >
                          <ArrowRight className="w-4 h-4" />
                        </button>
                      </div>

                      <div className="flex-1 overflow-hidden">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          targetPath={activeJumpPath}
                        />
                      </div>

                      <div className="flex items-center justify-between text-[10px] text-slate-500 font-bold uppercase tracking-widest px-1">
                        <span>{selectedPaths.size} Items Selected</span>
                        <button 
                          onClick={() => setSelectedPaths(new Set())}
                          className="hover:text-indigo-400"
                        >
                          Clear Scope
                        </button>
                      </div>
                    </div>
