                </div>
              </div>

              {/* Analysis & Context Column */}
              <div className="lg:col-span-7 space-y-4 flex flex-col">
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl flex-1 flex flex-col">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-2">
                      <Terminal className="w-5 h-5 text-indigo-400" />
                      <h3 className="text-sm font-bold text-white uppercase tracking-wider">Analysis Payload</h3>
                    </div>
                    <div className="flex items-center space-x-2 text-[10px] text-slate-500 font-bold">
                      <FileCode className="w-3.5 h-3.5" />
                      <span>SCHEMAS & LOGS SUPPORTED</span>
                    </div>
                  </div>

                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Provide additional context, manual logs, or specific audit instructions..."
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-xl p-4 text-slate-300 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all code-font text-sm mb-6 placeholder:text-slate-700 min-h-[300px]"
                  />

                  <div className="grid grid-cols-2 gap-4 mb-6">
                    <div className="p-3 bg-indigo-500/5 border border-indigo-500/10 rounded-xl">
                      <h4 className="text-[10px] font-bold text-indigo-400 uppercase mb-1">Retrieval Mode</h4>
                      <p className="text-xs text-slate-400 leading-tight">Reading raw buffers from system and interpreting structural schemas.</p>
