                </div>
              </div>
            </div>

            <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6 opacity-75">
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <Target className="w-6 h-6 text-indigo-400 mb-4" />
                <h3 className="text-white font-semibold mb-2 text-sm">Schema Validation</h3>
                <p className="text-xs text-slate-400">Verifies that agent behaviors conform to their defined system schemas.</p>
              </div>
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <MessageSquare className="w-6 h-6 text-emerald-400 mb-4" />
                <h3 className="text-white font-semibold mb-2 text-sm">Chat Drift Detection</h3>
                <p className="text-xs text-slate-400">Identifies conversational drift where agent goals diverge from the chat root.</p>
              </div>
              <div className="p-6 bg-slate-900/50 border border-slate-800 rounded-xl">
                <Search className="w-6 h-6 text-amber-400 mb-4" />
                <h3 className="text-white font-semibold mb-2 text-sm">Recursive Scan</h3>
                <p className="text-xs text-slate-400">Deeply traverses paths to find anomalies hidden in historical logs.</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard 
                title="Integrity Score" 
                value={`${data?.stats.alignmentScore}%`} 
                icon={Target} 
                color="bg-indigo-500" 
                subtext="Holistic Alignment Metric"
              />
              <StatCard 
                title="System Anomalies" 
                value={data?.stats.anomalyCount || 0} 
                icon={AlertOctagon} 
                color="bg-rose-500" 
                subtext="Detected in audit scope"
              />
              <StatCard 
                title="Drift Vectors" 
                value={data?.stats.criticalRisks || 0} 
                icon={Zap} 
                color="bg-amber-500" 
                subtext="Identified misalignment paths"
              />
              <StatCard 
                title="Sources Audited" 
                value={selectedPaths.size || 1} 
                icon={FolderOpen} 
                color="bg-emerald-500" 
                subtext="Total files interpreted"
              />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl">
                  <div className="flex items-center justify-between mb-6">
                    <div>
                      <h3 className="text-lg font-bold text-white">Anomaly Density Trend</h3>
                      <p className="text-xs text-slate-400">Time-series analysis of risk emergence</p>
                    </div>
                    <Activity className="w-5 h-5 text-indigo-400" />
                  </div>
                  <div className="h-64 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={data?.riskTrend}>
                        <defs>
                          <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                        <XAxis dataKey="time" stroke="#64748b" fontSize={10} tickLine={false} axisLine={false} />
                        <YAxis stroke="#64748b" fontSize={10} tickLine={false} axisLine={false} />
                        <Tooltip 
                          contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }}
                        />
                        <Area 
                          type="monotone" 
                          dataKey="score" 
                          stroke="#6366f1" 
                          fillOpacity={1} 
                          fill="url(#colorScore)" 
                          strokeWidth={2}
                        />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-xl">
                  <h3 className="text-lg font-bold text-white mb-4 flex items-center">
                    <ShieldCheck className="w-5 h-5 mr-2 text-indigo-400" />
                    Interpretative Audit Report
                  </h3>
                  <div className="p-4 bg-slate-950 rounded-xl border border-slate-800">
                    <p className="text-slate-300 leading-relaxed italic text-sm">
                      {data?.summary}
                    </p>
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                <h3 className="text-lg font-bold text-white flex items-center px-2">
                  <AlertOctagon className="w-5 h-5 mr-2 text-rose-400" />
                  Detailed Findings
                </h3>
                <div className="space-y-3">
                  {data?.anomalies.map((anomaly) => (
                    <AnomalyItem key={anomaly.id} anomaly={anomaly} />
                  ))}
                  {data?.anomalies.length === 0 && (
                    <div className="text-center py-12 text-slate-500 text-sm">No critical anomalies detected in scope.</div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 px-5 py-2.5 bg-slate-900/90 backdrop-blur-xl border border-slate-700/50 rounded-full flex items-center space-x-6 shadow-2xl z-50">
        <div className="flex -space-x-2">
          {[1, 2, 3].map(i => (
            <div key={i} className="w-6 h-6 rounded-full border-2 border-slate-900 bg-slate-800 flex items-center justify-center">
              <ShieldCheck className="w-3 h-3 text-indigo-400" />
            </div>
          ))}
        </div>
        <div className="h-4 w-px bg-slate-800" />
        <span className="text-[10px] font-bold tracking-widest text-slate-400 uppercase">Sentinel v2.6 Deep Retrieval</span>
      </div>
    </div>
  );
};

export default App;

