const categoryIcons = {
  [AnomalyCategory.MEMORY_PROTOCOL_VIOLATION]: <ShieldAlert className="w-3.5 h-3.5 mr-1 text-rose-400" />,
  [AnomalyCategory.SENTIMENT_MISALIGNMENT]: <Frown className="w-3.5 h-3.5 mr-1 text-orange-400" />,
