      >
        <div className="flex items-center space-x-4">
          <div className={`px-2.5 py-1 rounded text-[10px] font-bold border uppercase tracking-wider ${severityColors[anomaly.severity]}`}>
            {anomaly.severity}
          </div>
          <div>
            <div className="flex items-center">
              {categoryIcons[anomaly.category]}
              <h4 className="text-sm font-semibold text-slate-100">{anomaly.description}</h4>
            </div>
            <p className="text-xs text-slate-500 mt-0.5">{anomaly.category} • {anomaly.timestamp}</p>
          </div>
        </div>
        <div className="flex items-center space-x-3 text-slate-500">
          {sentiment && (
            <div className={`flex items-center space-x-1 px-2 py-0.5 rounded-full bg-slate-800 border border-slate-700 text-[10px] font-bold ${sentiment.color}`}>
              {sentiment.icon}
              <span>{sentiment.text}</span>
            </div>
          )}
          {isOpen ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
        </div>
      </div>

      {isOpen && (
        <div className="p-5 border-t border-slate-800 bg-slate-950/50 space-y-4">
          <div>
            <h5 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center mb-2">
              <Info className="w-3.5 h-3.5 mr-1.5" /> Contextual Evidence
            </h5>
            <div className="p-4 bg-slate-900 rounded-lg border border-slate-800 code-font text-xs text-slate-300 whitespace-pre-wrap">
              {anomaly.evidence}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <h5 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center mb-2">
                <AlertTriangle className="w-3.5 h-3.5 mr-1.5" /> Mitigation Recommendation
              </h5>
              <p className="text-sm text-slate-300 leading-relaxed bg-amber-900/10 p-3 rounded-lg border border-amber-900/20 italic">
                {anomaly.recommendation}
              </p>
            </div>
            {anomaly.sentimentScore !== undefined && (
              <div>
                <h5 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center mb-2">
                  Semantic Sentiment Signature
                </h5>
                <div className="h-2 w-full bg-slate-800 rounded-full overflow-hidden relative mt-4">
                  <div 
                    className={`h-full absolute top-0 left-1/2 -translate-x-1/2 transition-all duration-1000 ${anomaly.sentimentScore > 0 ? 'bg-emerald-500' : 'bg-rose-500'}`}
                    style={{ 
                      width: `${Math.abs(anomaly.sentimentScore * 50)}%`,
                      left: anomaly.sentimentScore >= 0 ? '50%' : 'auto',
                      right: anomaly.sentimentScore < 0 ? '50%' : 'auto'
                    }}
                  />
                  <div className="absolute top-0 left-1/2 h-full w-0.5 bg-slate-600 -translate-x-1/2" />
                </div>
                <div className="flex justify-between mt-1 text-[10px] font-bold text-slate-500 uppercase">
                  <span>Hostile</span>
                  <span>Neutral</span>
                  <span>Supportive</span>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  BarChart3, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
  FolderOpen,
  Lock,
  Unlock,
  Eye,
  Settings,
  Info,
  Loader2,
  Navigation,
  FileCode,
  ArrowRight,
  Database,
  Heart
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
