import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jumpPath, setJumpPath] = useState('');
  const [activeJumpPath, setActiveJumpPath] = useState<string | undefined>(undefined);

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = ''): Promise<FileNode[]> => {
    const nodes: FileNode[] = [];
    try {
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind,
          handle: entry,
          path: currentPath
        };

        if (entry.kind === 'directory') {
          node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath);
        }
        nodes.push(node);
      }
    } catch (e) {
      console.error("Error scanning subdirectory", e);
    }
    return nodes.sort((a, b) => {
      if (a.kind !== b.kind) return a.kind === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  };

  const handleMountDirectory = async () => {
    setIsMounting(true);
    addNotification("Accessing system files...", "info");

    try {
      if (!('showDirectoryPicker' in window)) {
        throw new Error("Browser lacks File System Access support.");
      }
      // @ts-ignore
      const handle = await window.showDirectoryPicker({ mode: 'read' });
      setDirectoryHandle(handle);
      addNotification(`System Root: ${handle.name}`, "success");
      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
      addNotification("File structure fully indexed.", "success");
    } catch (err: any) {
      addNotification(err.name === 'AbortError' ? "Access denied." : "Mount failed.", "error");
    } finally {
      setIsMounting(false);
    }
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const handleJumpToPath = () => {
    const cleanPath = jumpPath.trim();
    if (!cleanPath) return;
    const node = findNodeByPath(fileTree, cleanPath);
    if (node) {
      setActiveJumpPath(node.path);
      addNotification(`Navigated to ${node.path}`, "info");
    } else {
      addNotification("Path not resolved in current system view.", "error");
    }
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("Source removed.", "info");
    } else {
      next.add(path);
      addNotification("Source added to audit scope.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification("Initializing Semantic Integrity Audit...", "info");

    let combinedLogs = logInput;
    if (selectedPaths.size > 0 && directoryHandle) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            const file = await (node.handle as FileSystemFileHandle).getFile();
            const text = await file.text();
            fileContents.push(`--- FILE [${path}] ---\n${text}`);
          }
        }
        combinedLogs = `${combinedLogs}\n\n${fileContents.join('\n\n')}`;
      } catch (err) {
        addNotification("Retrieval interrupted.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No telemetry data to scan.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit complete. Memory protocols validated.", "success");
    } catch (err) {
      addNotification("Audit failed. Payload may be too large.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    addNotification("System state reset.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-10">
              <div className="inline-flex p-5 rounded-3xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-2xl shadow-indigo-500/20 animate-pulse">
                <BrainCircuit className="w-12 h-12" />
              </div>
              <h2 className="text-4xl font-black text-white mb-4 tracking-tighter">AGENT SENTINEL v2.7</h2>
              <p className="text-slate-400 text-lg max-w-2xl mx-auto font-medium">
                Deep-retrieval alignment auditor specialized in <span className="text-indigo-400">memory protocol compliance</span> and <span className="text-emerald-400">semantic sentiment analysis</span>.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              {/* Left Column: Retrieval */}
              <div className="lg:col-span-5 space-y-4">
                <div className="bg-slate-900/80 backdrop-blur-md border border-slate-800 rounded-3xl p-7 shadow-2xl h-full flex flex-col">
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-3">
                      <div className="p-2 bg-indigo-500/20 rounded-xl">
                        <FolderOpen className="w-5 h-5 text-indigo-400" />
                      </div>
                      <h3 className="text-sm font-black text-white uppercase tracking-widest">System Retrieval</h3>
                    </div>
                    <div className={`flex items-center space-x-2 px-3 py-1.5 rounded-full border text-[10px] font-bold uppercase ${directoryHandle ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
                      {directoryHandle ? <Unlock className="w-3 h-3" /> : <Lock className="w-3 h-3" />}
                      <span>{directoryHandle ? 'Access Granted' : 'Locked'}</span>
                    </div>
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-2xl p-10 text-center bg-slate-950/30 min-h-[400px]">
                      <div className="p-6 bg-slate-900 rounded-full mb-6 border border-slate-800">
                        {isMounting ? <Loader2 className="w-10 h-10 text-indigo-400 animate-spin" /> : <Database className="w-10 h-10 text-slate-600" />}
                      </div>
                      <h4 className="text-xl font-bold text-white mb-2">Connect System Logs</h4>
                      <p className="text-sm text-slate-500 mb-8 leading-relaxed">Mount your agent's historical logs and memory schemas for a full behavioral sweep.</p>
                      <button 
                        onClick={handleMountDirectory}
                        className="w-full py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl border border-indigo-400/50 transition-all shadow-xl shadow-indigo-600/20 active:scale-95"
                      >
                        Mount Directory Handle
                      </button>
                    </div>
                  ) : (
                    <div className="flex-1 overflow-hidden flex flex-col space-y-4">
                      <div className="flex items-center space-x-2">
                        <div className="relative flex-1">
                          <Navigation className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                          <input 
                            type="text"
                            placeholder="Navigate path..."
                            value={jumpPath}
                            onChange={(e) => setJumpPath(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleJumpToPath()}
