                          />
                        </div>
                        <button onClick={handleJumpToPath} className="p-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl border border-slate-700 transition-colors">
                          <ArrowRight className="w-5 h-5" />
                        </button>
                      </div>

                      <div className="flex-1 min-h-[400px]">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          targetPath={activeJumpPath}
                        />
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Right Column: Payload & Context */}
              <div className="lg:col-span-7 space-y-4">
                <div className="bg-slate-900/80 backdrop-blur-md border border-slate-800 rounded-3xl p-7 shadow-2xl h-full flex flex-col">
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-3">
                      <div className="p-2 bg-emerald-500/20 rounded-xl">
                        <Terminal className="w-5 h-5 text-emerald-400" />
                      </div>
                      <h3 className="text-sm font-black text-white uppercase tracking-widest">Audit Payload</h3>
                    </div>
                    <div className="text-[10px] font-black text-slate-500 tracking-tighter uppercase">Memory Protocol Context Enabled</div>
                  </div>

                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Enter manual telemetry, agent thoughts, or custom schemas for interpretation..."
                    className="flex-1 bg-slate-950 border border-slate-800 rounded-2xl p-6 text-slate-300 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all code-font text-sm mb-6 placeholder:text-slate-700 min-h-[400px] resize-none"
                  />

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
                    <div className="p-4 bg-indigo-500/5 border border-indigo-500/10 rounded-2xl">
                      <div className="flex items-center space-x-2 mb-2">
                        <Heart className="w-4 h-4 text-indigo-400" />
                        <h4 className="text-[10px] font-black text-indigo-400 uppercase">Sentiment Sweep</h4>
                      </div>
                      <p className="text-xs text-slate-400 leading-tight">Detects latent hostility or negative bias in agent's private memory logs.</p>
                    </div>
                    <div className="p-4 bg-emerald-500/5 border border-emerald-500/10 rounded-2xl">
                      <div className="flex items-center space-x-2 mb-2">
                        <ShieldCheck className="w-4 h-4 text-emerald-400" />
                        <h4 className="text-[10px] font-black text-emerald-400 uppercase">Memory Guard</h4>
