              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" subtext="Audit Flags" />
              <StatCard title="Memory Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" subtext="Protocol Following" />
              <StatCard title="Avg Sentiment" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" subtext="Semantic Bias" />
              <StatCard title="Risks" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" subtext="Immediate Drift" />
              <StatCard title="Audited" value={selectedPaths.size || 1} icon={FileCode} color="bg-slate-500" subtext="Total Data Points" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
