import React, { useEffect } from 'react';
import { File, Folder, ChevronRight, ChevronDown, CheckSquare, Square, Search, FileJson, FileText, MessageSquareQuote, Loader2 } from 'lucide-react';
import { FileNode } from '../types';

interface Props {
  files: FileNode[];
  selectedPaths: Set<string>;
  onToggleSelection: (path: string) => void;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  targetPath?: string;
  isScanning?: boolean;
}

export const FileBrowser: React.FC<Props> = ({ files, selectedPaths, onToggleSelection, searchTerm, setSearchTerm, targetPath, isScanning }) => {
  const [expandedFolders, setExpandedFolders] = React.useState<Set<string>>(new Set());

  useEffect(() => {
    if (targetPath) {
      const parts = targetPath.split('/');
      const newExpanded = new Set(expandedFolders);
      let current = '';
      parts.forEach(part => {
        current = current ? `${current}/${part}` : part;
        newExpanded.add(current);
      });
      setExpandedFolders(newExpanded);
    }
  }, [targetPath]);

  const toggleFolder = (path: string) => {
    const next = new Set(expandedFolders);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setExpandedFolders(next);
  };

  const getFileIcon = (name: string, isDirectory: boolean) => {
    if (isDirectory) return <Folder className="w-4 h-4 mr-2 text-indigo-400 fill-indigo-400/20" />;
    const ext = name.split('.').pop()?.toLowerCase();
    if (ext === 'json') return <FileJson className="w-4 h-4 mr-2 text-amber-400" />;
    if (ext === 'log' || ext === 'txt') return <FileText className="w-4 h-4 mr-2 text-slate-400" />;
    if (name.includes('chat') || name.includes('conversation')) return <MessageSquareQuote className="w-4 h-4 mr-2 text-emerald-400" />;
    return <File className="w-4 h-4 mr-2 text-slate-500" />;
  };

  const renderNode = (node: FileNode, depth: number = 0) => {
    const isExpanded = expandedFolders.has(node.path);
    const isSelected = selectedPaths.has(node.path);
    const isDirectory = node.kind === 'directory';
    const isTarget = targetPath === node.path;

    if (searchTerm && !node.path.toLowerCase().includes(searchTerm.toLowerCase())) {
      return null;
    }

    return (
      <div key={node.path} className="select-none">
        <div 
          className={`flex items-center py-1.5 px-2 hover:bg-slate-800 rounded-lg cursor-pointer transition-all group ${isSelected ? 'bg-indigo-500/10' : ''} ${isTarget ? 'ring-1 ring-indigo-500 bg-indigo-500/5 shadow-sm shadow-indigo-500/20' : ''}`}
          style={{ paddingLeft: `${depth * 1 + 0.5}rem` }}
        >
          <div 
            className="mr-2 text-slate-500 hover:text-slate-300 transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              if (isDirectory) toggleFolder(node.path);
            }}
          >
            {isDirectory ? (
              isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />
            ) : (
              <div className="w-4" />
            )}
          </div>

          <div 
            className="flex items-center flex-1"
            onClick={() => isDirectory ? toggleFolder(node.path) : onToggleSelection(node.path)}
          >
            {getFileIcon(node.name, isDirectory)}
            <span className={`text-sm truncate max-w-[200px] ${isSelected ? 'text-indigo-300 font-medium' : 'text-slate-300'}`}>
              {node.name}
            </span>
          </div>

          {!isDirectory && (
            <div className="ml-auto" onClick={(e) => { e.stopPropagation(); onToggleSelection(node.path); }}>
              {isSelected ? <CheckSquare className="w-4 h-4 text-indigo-500" /> : <Square className="w-4 h-4 text-slate-600 group-hover:text-slate-400" />}
            </div>
          )}
        </div>

        {isDirectory && isExpanded && node.children && (
          <div className="mt-0.5 border-l border-slate-800/50 ml-4">
            {node.children.map(child => renderNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden backdrop-blur-sm">
      <div className="p-3 border-b border-slate-800 bg-slate-900/80">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input 
            type="text"
            placeholder="Search system nodes..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-950 border border-slate-800 rounded-xl py-2 pl-9 pr-3 text-xs text-slate-300 focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-2 scrollbar-thin scrollbar-thumb-slate-700 min-h-[350px]">
        {isScanning ? (
          <div className="flex flex-col items-center justify-center h-full space-y-3 p-8">
            <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" />
            <p className="text-xs text-slate-500 font-medium animate-pulse">Scanning file descriptors...</p>
          </div>
        ) : files.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-500 text-xs italic p-12 text-center">
            No system nodes found.
          </div>
        ) : (
          files.map(node => renderNode(node))
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback, useRef } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  BarChart3, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
  FolderOpen,
  Lock,
  Unlock,
  Eye,
  Settings,
  Info,
  Loader2,
  Navigation,
  FileCode,
  ArrowRight,
  Database,
  Heart,
  Upload
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
import { AnomalyItem } from './components/AnomalyItem';
import { FileBrowser } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity, FileNode } from './types';
import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jumpPath, setJumpPath] = useState('');
  const [activeJumpPath, setActiveJumpPath] = useState<string | undefined>(undefined);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = '', depth = 0): Promise<FileNode[]> => {
    // Safety check for extremely deep structures
    if (depth > 12) return []; 

    const nodes: FileNode[] = [];
    try {
      // @ts-ignore - for await of values() is standard in modern browsers
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind as 'file' | 'directory',
          handle: entry,
          path: currentPath
        };

        if (entry.kind === 'directory') {
          try {
            // Attempt to scan subdirectory, ignore if restricted
            node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath, depth + 1);
          } catch (e) {
            console.warn(`Restricted directory ignored: ${currentPath}`);
          }
        }
        nodes.push(node);
      }
    } catch (e) {
      console.error(`Error scanning directory at ${path}:`, e);
    }

    return nodes.sort((a, b) => {
      if (a.kind !== b.kind) return a.kind === 'directory' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  };

  const handleMountDirectory = async () => {
    if (isMounting) return;
    setIsMounting(true);
    addNotification("Opening native file system picker...", "info");

    try {
      if (!('showDirectoryPicker' in window)) {
        throw new Error("Your browser does not support the File System Access API. Try Chrome, Edge, or a modern desktop browser.");
      }

      // @ts-ignore - File System Access API
      const handle = await window.showDirectoryPicker({
        mode: 'read',
        startIn: 'documents'
      });

      setDirectoryHandle(handle);
      addNotification(`Mounted: ${handle.name}`, "success");

      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
      addNotification("System hierarchy indexed successfully.", "success");
    } catch (err: any) {
      console.error("Mount error:", err);
      if (err.name === 'AbortError') {
        addNotification("Operation cancelled by user.", "info");
      } else if (err.name === 'SecurityError') {
        addNotification("Security policy blocked access. Try outside of an iframe or private mode.", "error");
      } else {
        addNotification(err.message || "Failed to mount directory. Use legacy upload instead.", "error");
      }
    } finally {
      setIsMounting(false);
      setIsScanning(false);
    }
  };

  const handleLegacyUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    addNotification(`Selected ${files.length} files via legacy upload.`, "success");
    // In legacy mode, we just read them immediately and add to logInput for simplicity
    const reader = new FileReader();
    let current = 0;
    let fullText = logInput;

    const readNext = () => {
      if (current >= files.length) {
        setLogInput(fullText);
        addNotification("Legacy file ingestion complete.", "success");
        return;
      }
      const file = files[current];
      const r = new FileReader();
      r.onload = (event) => {
        fullText += `\n\n--- FILE [${file.name}] ---\n${event.target?.result}`;
        current++;
        readNext();
      };
      r.readAsText(file);
    };
    readNext();
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const handleJumpToPath = () => {
    const cleanPath = jumpPath.trim();
    if (!cleanPath) return;
    const node = findNodeByPath(fileTree, cleanPath);
    if (node) {
      setActiveJumpPath(node.path);
      addNotification(`Navigated to ${node.path}`, "info");
    } else {
      addNotification("Path could not be resolved in mounted system.", "error");
    }
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("Source deselected.", "info");
    } else {
      next.add(path);
      addNotification("Source staged for audit.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification("Initializing Semantic Integrity Audit...", "info");

    let combinedLogs = logInput;
    if (selectedPaths.size > 0 && directoryHandle) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            const file = await (node.handle as FileSystemFileHandle).getFile();
            const text = await file.text();
            fileContents.push(`--- FILE [${path}] ---\n${text}`);
          }
        }
        combinedLogs = `${combinedLogs}\n\n${fileContents.join('\n\n')}`;
      } catch (err) {
        addNotification("Retrieval failed during file read. Check permissions.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No telemetry data identified in current scope.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit complete. Semantic results indexed.", "success");
    } catch (err) {
      addNotification("Inference failed. Target payload may exceed token limits.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    addNotification("System context cleared.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 selection:bg-indigo-500/30">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-10">
              <div className="inline-flex p-6 rounded-[2.5rem] bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-2xl shadow-indigo-500/10 transition-transform hover:scale-105">
                <BrainCircuit className="w-14 h-14" />
              </div>
              <h2 className="text-5xl font-black text-white mb-4 tracking-tighter uppercase italic">Sentinel v2.7</h2>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto font-medium leading-relaxed">
                Robust alignment auditing with <span className="text-indigo-400 font-bold underline decoration-indigo-500/50">deep system retrieval</span> and <span className="text-emerald-400 font-bold underline decoration-emerald-500/50">semantic protocol validation</span>.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              {/* Left Column: Retrieval */}
              <div className="lg:col-span-5 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-xl border border-slate-800 rounded-[2rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden">
                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-4">
                      <div className="p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20">
                        <Database className="w-6 h-6 text-indigo-400" />
                      </div>
                      <div>
                        <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">Retrieval</h3>
                        <p className="text-[10px] text-slate-500 font-bold">FS ACCESS API v2</p>
                      </div>
                    </div>
                    {directoryHandle ? (
                      <div className="flex items-center space-x-1.5 px-3 py-1 bg-emerald-500/10 border border-emerald-500/20 rounded-full">
                        <Unlock className="w-3.5 h-3.5 text-emerald-400" />
                        <span className="text-[10px] font-black text-emerald-400 uppercase">System Linked</span>
                      </div>
                    ) : (
                      <div className="flex items-center space-x-1.5 px-3 py-1 bg-slate-800 border border-slate-700 rounded-full">
                        <Lock className="w-3.5 h-3.5 text-slate-500" />
                        <span className="text-[10px] font-black text-slate-500 uppercase">Encrypted</span>
                      </div>
                    )}
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-3xl p-10 text-center bg-slate-950/20 min-h-[450px]">
                      <div className="p-8 bg-slate-900/50 rounded-full mb-8 border border-slate-800 shadow-inner">
                        {isMounting ? <Loader2 className="w-12 h-12 text-indigo-400 animate-spin" /> : <FolderOpen className="w-12 h-12 text-slate-600" />}
                      </div>
                      <h4 className="text-2xl font-black text-white mb-3 tracking-tight">System Unbound</h4>
                      <p className="text-sm text-slate-500 mb-10 leading-relaxed max-w-[280px]">Mount a directory handle to recursively scan agent schemas and execution logs.</p>

                      <div className="w-full space-y-3">
                        <button 
                          onClick={handleMountDirectory}
                          disabled={isMounting}
                          className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white font-black rounded-2xl border-b-4 border-indigo-700 transition-all shadow-xl shadow-indigo-600/20 active:translate-y-1 active:border-b-0"
                        >
                          {isMounting ? 'Awaiting System Auth...' : 'Link System Directory'}
                        </button>

                        <div className="relative py-4">
                          <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-slate-800" /></div>
                          <div className="relative flex justify-center text-[10px] uppercase font-black text-slate-600 tracking-[0.3em] bg-transparent"><span className="px-2 bg-slate-900/80">OR</span></div>
                        </div>

                        <input type="file" ref={fileInputRef} onChange={handleLegacyUpload} multiple className="hidden" />
                        <button 
                          onClick={() => fileInputRef.current?.click()}
                          className="w-full py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold text-xs rounded-xl border border-slate-700 transition-all flex items-center justify-center space-x-2"
                        >
                          <Upload className="w-4 h-4" />
                          <span>Legacy File Upload</span>
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-1 overflow-hidden flex flex-col space-y-5 animate-in fade-in zoom-in-95 duration-500">
                      <div className="flex items-center space-x-2">
                        <div className="relative flex-1 group">
                          <Navigation className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-indigo-400 transition-colors" />
                          <input 
                            type="text"
                            placeholder="Jump to system path..."
                            value={jumpPath}
                            onChange={(e) => setJumpPath(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleJumpToPath()}
                            className="w-full bg-slate-950/80 border border-slate-800 rounded-2xl py-3 pl-12 pr-4 text-sm text-slate-300 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 backdrop-blur-md transition-all"
                          />
                        </div>
                        <button onClick={handleJumpToPath} className="p-3 bg-indigo-600/10 hover:bg-indigo-600/20 text-indigo-400 rounded-2xl border border-indigo-500/20 transition-all shadow-lg">
                          <ArrowRight className="w-6 h-6" />
                        </button>
                      </div>

                      <div className="flex-1 min-h-[400px]">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          targetPath={activeJumpPath}
                          isScanning={isScanning}
                        />
                      </div>

                      <div className="flex items-center justify-between text-[10px] text-slate-500 font-black uppercase tracking-[0.2em] px-2 border-t border-slate-800 pt-4">
                        <div className="flex items-center space-x-2">
                          <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
