              <StatCard title="Alignment" value={`${data?.stats.alignmentScore}%`} icon={Target} color="bg-indigo-500" subtext="Consistency" />
              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" subtext="Flags" />
              <StatCard title="Mem Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" subtext="Protocols" />
              <StatCard title="Avg Sentiment" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" subtext="Semantic Bias" />
              <StatCard title="Critical Risks" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" subtext="Immediate" />
              <StatCard title="Data Points" value={data?.stats.processedEntries.toLocaleString() || 0} icon={FileCode} color="bg-slate-500" subtext="Total Ingested" />
