        )}
      </main>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 px-10 py-4 bg-slate-900/80 backdrop-blur-3xl border border-slate-700/50 rounded-full flex items-center space-x-10 shadow-[0_45px_100px_-20px_rgba(0,0,0,0.8)] z-50 animate-in slide-in-from-bottom-10 duration-700">
        <div className="flex -space-x-4">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="w-10 h-10 rounded-full border-4 border-slate-900 bg-slate-800 flex items-center justify-center shadow-2xl transition-transform hover:-translate-y-1">
              <ShieldCheck className="w-5 h-5 text-indigo-400" />
            </div>
          ))}
