        <div className="h-8 w-px bg-slate-700" />
        <div className="flex flex-col">
          <span className="text-xs font-black tracking-[0.3em] text-white uppercase">Sentinel v2.7.2</span>
          <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Autonomous Deep Retrieval Engine</span>
        </div>
