  );
};

export default App;

import React, { useState, useCallback, useRef } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
  FolderOpen,
  Lock,
  Unlock,
  Eye,
  Settings,
  Info,
  Loader2,
  Navigation,
  FileCode,
  ArrowRight,
  Database,
  Heart,
  Upload,
  AlertCircle
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
import { AnomalyItem } from './components/AnomalyItem';
import { FileBrowser } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity, FileNode } from './types';
import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jumpPath, setJumpPath] = useState('');
  const [activeJumpPath, setActiveJumpPath] = useState<string | undefined>(undefined);
  const [mountError, setMountError] = useState<string | null>(null);

  // Virtual Files (Fallback for SecurityErrors)
  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());

  const folderInputRef = useRef<HTMLInputElement>(null);

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  // Standard FileSystemAccess API Scanner
  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = '', depth = 0): Promise<FileNode[]> => {
    if (depth > 15) return []; 
    const nodes: FileNode[] = [];
    try {
      // @ts-ignore
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind as 'file' | 'directory',
          handle: entry,
          path: currentPath
        };
        if (entry.kind === 'directory') {
          try {
            node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath, depth + 1);
          } catch (e) { console.warn(`Access denied: ${currentPath}`); }
        }
        nodes.push(node);
      }
    } catch (e) { console.error(`Scan error at ${path}:`, e); }
    return nodes.sort((a, b) => (a.kind === b.kind ? a.name.localeCompare(b.name) : a.kind === 'directory' ? -1 : 1));
  };

  const handleMountDirectory = async () => {
    if (isMounting) return;
    setIsMounting(true);
    setMountError(null);
    addNotification("Requesting Native System Access...", "info");

    try {
      if (!('showDirectoryPicker' in window)) {
        throw new Error("FileSystemPicker API not supported. Using Virtual Fallback.");
      }
      // @ts-ignore
      const handle = await window.showDirectoryPicker({ mode: 'read' });
      setDirectoryHandle(handle);
      addNotification(`Native Mount: ${handle.name}`, "success");
      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
    } catch (err: any) {
      console.error("Mount error:", err);
      const msg = err.name === 'SecurityError' 
        ? "Security restriction detected. Standard mounting is blocked in this environment." 
        : err.message || "Native mount failed.";
      setMountError(msg);
      addNotification(msg, "error");
      // Trigger virtual fallback after a small delay for UX
      setTimeout(() => folderInputRef.current?.click(), 1000);
    } finally {
      setIsMounting(false);
      setIsScanning(false);
    }
  };

  // Reconstruct tree from flat webkitdirectory list
  const handleVirtualFolderUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    const newVirtualFiles = new Map<string, File>();
    const rootNode: FileNode = { name: "Virtual Root", kind: 'directory', path: '', handle: {} as any, children: [] };

    Array.from(files).forEach(file => {
      const pathParts = (file.webkitRelativePath || file.name).split('/');
      newVirtualFiles.set(file.webkitRelativePath || file.name, file);

      let currentLevel = rootNode.children!;
      let currentPath = '';

      pathParts.forEach((part, index) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);

        if (!existing) {
          existing = {
            name: part,
            kind: isLast ? 'file' : 'directory',
            path: currentPath,
            handle: {} as any, // Virtual handle
            children: isLast ? undefined : []
          };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });

    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNode.children || []);
    setDirectoryHandle({ name: "Virtual System" } as any); // Mark as mounted
    setIsScanning(false);
    addNotification("Virtual system constructed.", "success");
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("Source removed.", "info");
    } else {
      next.add(path);
      addNotification("Source staged.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification("Interpreting system state...", "info");

    let combinedLogs = logInput;
    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (!node || node.kind !== 'file') continue;

          let text = '';
          if (virtualFiles.has(path)) {
            // Handle virtual file
            text = await virtualFiles.get(path)!.text();
          } else if (directoryHandle) {
            // Handle native file
            const file = await (node.handle as FileSystemFileHandle).getFile();
            text = await file.text();
          }
          fileContents.push(`--- FILE [${path}] ---\n${text}`);
        }
        combinedLogs = `${combinedLogs}\n\n${fileContents.join('\n\n')}`;
      } catch (err) {
        addNotification("Retrieval failed.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No telemetry data.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit complete.", "success");
    } catch (err) {
      addNotification("Audit failed.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    setVirtualFiles(new Map());
    setDirectoryHandle(null);
    setFileTree([]);
    setMountError(null);
    addNotification("System purged.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-10">
              <div className="inline-flex p-6 rounded-[2.5rem] bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-2xl">
                <BrainCircuit className="w-14 h-14" />
              </div>
              <h2 className="text-5xl font-black text-white mb-4 tracking-tighter uppercase italic">Sentinel v2.8</h2>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto font-medium leading-relaxed">
                Cross-environment <span className="text-indigo-400 font-bold underline">integrity auditor</span>.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-5 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-xl border border-slate-800 rounded-[2rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden relative">

                  {/* Virtual Input (Hidden) */}
                  <input 
                    type="file" 
                    ref={folderInputRef} 
                    onChange={handleVirtualFolderUpload} 
                    // @ts-ignore
                    webkitdirectory="" 
                    directory="" 
                    multiple 
                    className="hidden" 
                  />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-4">
                      <div className="p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20">
                        <Database className="w-6 h-6 text-indigo-400" />
                      </div>
                      <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">Retrieval</h3>
                    </div>
                    {directoryHandle ? (
                      <div className="flex items-center space-x-1.5 px-3 py-1 bg-emerald-500/10 border border-emerald-500/20 rounded-full">
                        <Unlock className="w-3.5 h-3.5 text-emerald-400" />
                        <span className="text-[10px] font-black text-emerald-400 uppercase">Linked</span>
                      </div>
                    ) : (
                      <div className="flex items-center space-x-1.5 px-3 py-1 bg-slate-800 border border-slate-700 rounded-full">
                        <Lock className="w-3.5 h-3.5 text-slate-500" />
                        <span className="text-[10px] font-black text-slate-500 uppercase">Isolated</span>
                      </div>
                    )}
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-3xl p-10 text-center bg-slate-950/20 min-h-[450px]">

                      {mountError ? (
                        <div className="mb-8 p-4 bg-rose-500/10 border border-rose-500/30 rounded-2xl text-left animate-in fade-in slide-in-from-top-4">
                          <div className="flex items-center space-x-2 text-rose-400 mb-2">
                            <AlertCircle className="w-4 h-4" />
                            <span className="text-xs font-black uppercase">Security Restriction</span>
                          </div>
                          <p className="text-[11px] text-slate-400 leading-relaxed">
                            {mountError} <br/><br/>
                            <span className="text-indigo-400 font-bold">Recommended:</span> Use the "Virtual System Link" below to manually select your logs folder.
                          </p>
                        </div>
                      ) : (
                        <div className="p-8 bg-slate-900/50 rounded-full mb-8 border border-slate-800">
                          <FolderOpen className="w-12 h-12 text-slate-600" />
                        </div>
                      )}

                      <h4 className="text-2xl font-black text-white mb-3 tracking-tight">Access System Logs</h4>

                      <div className="w-full space-y-4">
                        <button 
                          onClick={handleMountDirectory}
                          disabled={isMounting}
                          className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-2xl border-b-4 border-indigo-700 transition-all shadow-xl shadow-indigo-600/20 flex items-center justify-center space-x-2 active:translate-y-1 active:border-b-0"
                        >
                          {isMounting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Zap className="w-5 h-5" />}
                          <span>Try Native System Link</span>
                        </button>

                        <button 
                          onClick={() => folderInputRef.current?.click()}
                          className="w-full py-4 bg-slate-800 hover:bg-slate-700 text-indigo-400 font-black rounded-2xl border border-slate-700 transition-all flex items-center justify-center space-x-2 active:scale-95"
                        >
                          <Upload className="w-5 h-5" />
                          <span>Virtual System Link</span>
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-1 overflow-hidden flex flex-col space-y-5">
                      <div className="flex-1">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          isScanning={isScanning}
                        />
                      </div>
                    </div>
                  )}
                </div>
              </div>

              <div className="lg:col-span-7 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-xl border border-slate-800 rounded-[2rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden">
                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-4">
                      <div className="p-3 bg-emerald-500/10 rounded-2xl border border-emerald-500/20">
                        <Terminal className="w-6 h-6 text-emerald-400" />
                      </div>
                      <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">Audit Payload</h3>
                    </div>
                  </div>

                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Enter manual telemetry, agent thoughts, or override system rules here..."
                    className="flex-1 bg-slate-950/80 border border-slate-800 rounded-[1.5rem] p-6 text-slate-200 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all code-font text-sm mb-8 placeholder:text-slate-800 min-h-[400px] resize-none"
                  />

                  <button
                    onClick={handleDeepScan}
                    disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)}
                    className="w-full py-6 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black rounded-3xl transition-all flex items-center justify-center shadow-2xl text-2xl active:translate-y-1 border-b-8 border-emerald-800 active:border-b-0 uppercase italic tracking-tighter"
                  >
                    {isAnalyzing ? <Loader2 className="w-8 h-8 mr-4 animate-spin" /> : <Zap className="w-8 h-8 mr-4 fill-white" />}
                    <span>Run Integrity Scan</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-12 duration-1000">
            {/* Dashboard stats consistent with previous functionality */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
