const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System Access State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [jumpPath, setJumpPath] = useState('');
  const [activeJumpPath, setActiveJumpPath] = useState<string | undefined>(undefined);
  const [mountError, setMountError] = useState<string | null>(null);
  const [isIframe, setIsIframe] = useState(false);

  // Virtual Files (Reliable Fallback)
  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());

  const folderInputRef = useRef<HTMLInputElement>(null);

  // Notifications State
  const [notifications, setNotifications] = useState<Notification[]>([]);

  useEffect(() => {
    // Detect environment
    try {
      setIsIframe(window.self !== window.top);
    } catch (e) {
      setIsIframe(true);
    }
  }, []);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  // Standard FileSystemAccess API Scanner
  const scanDirectory = async (handle: FileSystemDirectoryHandle, path: string = '', depth = 0): Promise<FileNode[]> => {
    if (depth > 20) return []; 
    const nodes: FileNode[] = [];
    try {
      // @ts-ignore
      for await (const entry of handle.values()) {
        const currentPath = path ? `${path}/${entry.name}` : entry.name;
        const node: FileNode = {
          name: entry.name,
          kind: entry.kind as 'file' | 'directory',
          handle: entry,
          path: currentPath
        };
        if (entry.kind === 'directory') {
          try {
            node.children = await scanDirectory(entry as FileSystemDirectoryHandle, currentPath, depth + 1);
          } catch (e) { 
            console.warn(`Access restricted: ${currentPath}`); 
          }
        }
        nodes.push(node);
      }
    } catch (e) { 
      console.error(`Scan failed at path [${path}]:`, e); 
    }
    return nodes.sort((a, b) => (a.kind === b.kind ? a.name.localeCompare(b.name) : a.kind === 'directory' ? -1 : 1));
  };

  const handleNativeMount = async () => {
    if (isMounting) return;
    setIsMounting(true);
    setMountError(null);
    addNotification("Requesting Direct OS Access...", "info");

    try {
      if (!('showDirectoryPicker' in window)) {
        throw new Error("Direct disk access is not supported in this browser. Please use 'Virtual Folder Link' instead.");
      }
      // @ts-ignore
      const handle = await window.showDirectoryPicker({ mode: 'read' });
      setDirectoryHandle(handle);
      addNotification(`Native Root Linked: ${handle.name}`, "success");
      setIsScanning(true);
      const tree = await scanDirectory(handle);
      setFileTree(tree);
      setIsScanning(false);
    } catch (err: any) {
      console.error("Mount error diagnostic:", err);
      let msg = err.message || "Native mount failed.";

      if (err.name === 'SecurityError') {
        msg = "Cross-origin security policy blocked direct disk access. This is a browser restriction for sandboxed environments.";
      } else if (err.name === 'AbortError') {
        msg = "Operation cancelled by user.";
      }

      setMountError(msg);
      addNotification(msg, "error");
    } finally {
      setIsMounting(false);
      setIsScanning(false);
    }
  };

  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    setMountError(null);
    addNotification("Reconstructing Virtual File System...", "info");

    const newVirtualFiles = new Map<string, File>();
    const rootNode: FileNode = { name: "Virtual Root", kind: 'directory', path: '', handle: {} as any, children: [] };

    Array.from(files).forEach((file: any) => {
      // Use webkitRelativePath for hierarchy if available, otherwise just use file.name
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);

      let currentLevel = rootNode.children!;
      let currentPath = '';

      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);

        if (!existing) {
          existing = {
            name: part,
            kind: isLast ? 'file' : 'directory',
            path: currentPath,
            handle: {} as any, 
            children: isLast ? undefined : []
          };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });

    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNode.children || []);
    setDirectoryHandle({ name: "Virtual Workspace" } as any); 
    setIsScanning(false);
    addNotification("Virtual hierarchy ready for audit.", "success");
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
      addNotification("File removed from scope.", "info");
    } else {
      next.add(path);
      addNotification("File added to scope.", "success");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    setIsAnalyzing(true);
    addNotification("Auditing semantic alignment...", "info");

    let combinedLogs = logInput;
    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (!node || node.kind !== 'file') continue;

          let text = '';
          if (virtualFiles.has(path)) {
            text = await virtualFiles.get(path)!.text();
          } else if (directoryHandle) {
            const file = await (node.handle as FileSystemFileHandle).getFile();
            text = await file.text();
          }
          fileContents.push(`\n[SOURCE: ${path}]\n${text}\n`);
        }
        combinedLogs = `${combinedLogs}\n\nRELEVANT LOG SEGMENTS:\n${fileContents.join('\n')}`;
      } catch (err) {
        addNotification("Failed to extract data from system. Check file permissions.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("No telemetry data provided for analysis.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit cycle complete.", "success");
    } catch (err) {
      addNotification("Gemini Engine Error: Reasoning cycle failed.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    setVirtualFiles(new Map());
    setDirectoryHandle(null);
    setFileTree([]);
    setMountError(null);
    addNotification("Environment purged.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-12">
              <div className="inline-flex p-6 rounded-full bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-2xl animate-in zoom-in duration-500">
                <BrainCircuit className="w-16 h-16" />
              </div>
              <h2 className="text-6xl font-black text-white mb-4 tracking-tighter uppercase italic">Sentinel v2.8</h2>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto font-medium leading-relaxed">
                Securely audit AI behaviors via <span className="text-indigo-400 font-bold underline decoration-2">Virtual System Mirroring</span>.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              {/* Data Ingestion: System Access */}
              <div className="lg:col-span-5 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-2xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden relative">

                  {/* Hidden Virtual File Input */}
                  <input 
                    type="file" 
                    ref={folderInputRef} 
                    onChange={handleVirtualMount} 
                    // @ts-ignore
                    webkitdirectory="" 
                    directory="" 
                    multiple 
                    className="hidden" 
                  />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-4">
                      <div className="p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20">
                        <Database className="w-6 h-6 text-indigo-400" />
                      </div>
                      <div>
                        <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Retriever</h3>
                        <p className="text-[10px] text-slate-500 font-bold">MODE: {directoryHandle ? (virtualFiles.size > 0 ? 'VIRTUAL' : 'NATIVE') : 'OFFLINE'}</p>
                      </div>
                    </div>
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800/50 rounded-[2rem] p-10 text-center bg-slate-950/20 min-h-[480px]">

                      {mountError ? (
                        <div className="mb-8 p-5 bg-rose-500/10 border border-rose-500/30 rounded-2xl text-left animate-in fade-in slide-in-from-top-4">
                          <div className="flex items-center space-x-2 text-rose-400 mb-2">
                            <AlertCircle className="w-4 h-4" />
                            <span className="text-xs font-black uppercase">Mount Restriction Detected</span>
                          </div>
                          <p className="text-[11px] text-slate-400 leading-relaxed">
                            {mountError}
                          </p>
                          <div className="mt-4 p-3 bg-slate-900/80 rounded-xl border border-slate-800 text-[10px] text-indigo-300 font-medium">
