                        >
                          Disconnect System Source
                        </button>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Payload & Core Action */}
              <div className="lg:col-span-7 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-2xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden">
                  <div className="flex items-center justify-between mb-8">
