        <div className="h-10 w-px bg-slate-700" />
        <div className="flex flex-col">
          <span className="text-xs font-black tracking-[0.3em] text-white uppercase leading-none mb-1">Sentinel v2.8.2</span>
          <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-none">Unified Retrieval & Alignment Core</span>
        </div>
      </div>
    </div>
  );
};

