import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
