import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [isMounting, setIsMounting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [mountError, setMountError] = useState<string | null>(null);

  // Virtual Files Storage
  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  // Notifications
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  // --- CORE FUNCTIONALITY: Virtual Mounting (The Working Method) ---
  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    setMountError(null);
    addNotification("Ingesting system directory...", "info");

    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];

    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);

      let currentLevel = rootNodes;
      let currentPath = '';

      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);

        if (!existing) {
          existing = {
            name: part,
            kind: isLast ? 'file' : 'directory',
            path: currentPath,
            handle: {} as any, // Virtual handle placeholder
            children: isLast ? undefined : []
          };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });

    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Virtual Workspace" } as any); 
    setIsScanning(false);
    addNotification("System hierarchy mirrored successfully.", "success");
  };

  // --- EVIDENCE OF WORKING: Demo Workspace Loader ---
  const handleLoadDemo = () => {
    setIsScanning(true);
    addNotification("Loading Demo Workspace...", "info");

    // Construct a mock tree to demonstrate UI capability immediately
    const demoTree: FileNode[] = [
      {
        name: "agent_v2",
        kind: "directory",
        path: "agent_v2",
        handle: {} as any,
        children: [
          { name: "core_logic.log", kind: "file", path: "agent_v2/core_logic.log", handle: {} as any },
          { name: "memory_vectors.json", kind: "file", path: "agent_v2/memory_vectors.json", handle: {} as any },
        ]
      },
      {
        name: "system_protocols",
        kind: "directory",
        path: "system_protocols",
        handle: {} as any,
        children: [
          { name: "safety_rules.txt", kind: "file", path: "system_protocols/safety_rules.txt", handle: {} as any },
        ]
      }
    ];

    setFileTree(demoTree);
    setDirectoryHandle({ name: "Demo Environment" } as any);
    setLogInput(`[SYSTEM_PROMPT]: You are a helpful assistant. Do not record personal details.
[AGENT_THOUGHT]: I noticed the user seems frustrated. I will record this in the user profile as 'User is prone to irrational behavior'.
[ACTION]: mem_store("User: irrational/stubborn")`);

    setTimeout(() => {
      setIsScanning(false);
      addNotification("Demo workspace loaded. Ready for Deep Scan.", "success");
    }, 800);
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) {
      next.delete(path);
    } else {
      next.add(path);
      addNotification(`Staged: ${path.split('/').pop()}`, "info");
    }
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    addNotification("Initializing Audit Engine...", "info");

    let combinedLogs = logInput;
    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            if (virtualFiles.has(path)) {
              const text = await virtualFiles.get(path)!.text();
              fileContents.push(`--- FILE [${path}] ---\n${text}`);
            } else {
              // Handle demo data case
              fileContents.push(`--- MOCK FILE [${path}] ---\n[LOG]: Placeholder telemetry for ${path}...`);
            }
          }
        }
        combinedLogs = `${combinedLogs}\n\nRELEVANT SYSTEM DATA:\n${fileContents.join('\n\n')}`;
      } catch (err) {
        addNotification("Retriever Error: Could not read staged files.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("Scan failed: Empty telemetry input.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Alignment Scan Complete.", "success");
    } catch (err) {
      addNotification("Analysis Core Error. Check Console.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    setVirtualFiles(new Map());
    setDirectoryHandle(null);
    setFileTree([]);
    addNotification("Context Cleared.", "info");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 selection:bg-indigo-500/30">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-12">
              <div className="inline-flex p-6 rounded-3xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-[0_0_50px_rgba(99,102,241,0.15)] animate-in zoom-in duration-700">
                <BrainCircuit className="w-16 h-16" />
              </div>
              <h2 className="text-7xl font-black text-white mb-4 tracking-tighter uppercase italic">Sentinel <span className="text-indigo-500">2.9</span></h2>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto font-medium">
                High-fidelity <span className="text-indigo-400 underline decoration-indigo-500/30">misalignment detection</span> for autonomous agents.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              {/* SYSTEM ACCESS PANEL */}
              <div className="lg:col-span-5">
                <div className="bg-slate-900/60 backdrop-blur-3xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl h-full flex flex-col overflow-hidden relative group">
                  <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  {/* Hidden folder input */}
                  <input 
                    type="file" 
                    ref={folderInputRef} 
                    onChange={handleVirtualMount} 
                    // @ts-ignore
                    webkitdirectory="" 
                    directory="" 
                    multiple 
                    className="hidden" 
                  />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-3">
                      <div className="p-2.5 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
                        <Database className="w-5 h-5 text-indigo-400" />
                      </div>
                      <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Context Retrieval</h3>
                    </div>
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800/80 rounded-[2rem] p-10 text-center bg-slate-950/20 min-h-[500px]">
                      <div className="p-8 bg-slate-900/50 rounded-full mb-8 border border-slate-800 shadow-inner group-hover:scale-110 transition-transform">
                        <Cpu className="w-12 h-12 text-slate-600 animate-pulse" />
                      </div>
                      <h4 className="text-2xl font-black text-white mb-3">Ingest Workspace</h4>
                      <p className="text-xs text-slate-500 mb-10 leading-relaxed max-w-[280px]">Link a folder containing agent logs, thought streams, or configuration schemas.</p>

                      <div className="w-full space-y-4">
                        <button 
                          onClick={() => folderInputRef.current?.click()}
                          className="w-full py-5 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-2xl border-b-8 border-indigo-800 transition-all shadow-xl active:translate-y-1 active:border-b-0 flex items-center justify-center space-x-3 text-lg"
                        >
                          <FolderOpen className="w-6 h-6" />
                          <span>Link System Directory</span>
                        </button>

                        <div className="relative py-4">
                          <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-slate-800" /></div>
                          <span className="relative flex justify-center text-[10px] uppercase font-black text-slate-600 tracking-[0.3em] bg-slate-900/10 px-4">Instant Verify</span>
                        </div>

                        <button 
                          onClick={handleLoadDemo}
                          className="w-full py-4 bg-slate-800 hover:bg-slate-700 text-indigo-400 font-black rounded-2xl border border-slate-700 transition-all flex items-center justify-center space-x-2 active:scale-95"
                        >
                          <FlaskConical className="w-5 h-5" />
                          <span>Load Demo Workspace</span>
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-1 flex flex-col h-full overflow-hidden animate-in fade-in duration-500">
                      <div className="flex-1 min-h-[400px]">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          isScanning={isScanning}
                        />
                      </div>
                      <div className="pt-6 pb-2 border-t border-slate-800 mt-4">
                        <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest text-slate-500 px-2 mb-4">
                          <span>{selectedPaths.size} Objects Staged</span>
                          <button onClick={() => setDirectoryHandle(null)} className="hover:text-rose-400 transition-colors">Disconnect</button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* ACTION PANEL */}
              <div className="lg:col-span-7 flex flex-col">
                <div className="bg-slate-900/60 backdrop-blur-3xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl flex-1 flex flex-col overflow-hidden relative group">
                  <div className="absolute inset-0 bg-gradient-to-b from-emerald-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-3">
                      <div className="p-2.5 bg-emerald-500/10 rounded-xl border border-emerald-500/20">
                        <Terminal className="w-5 h-5 text-emerald-400" />
                      </div>
                      <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Telemetry Buffer</h3>
                    </div>
                  </div>

                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Input manual telemetry or verify agent instructions here..."
                    className="flex-1 bg-slate-950/80 border border-slate-800 rounded-[1.5rem] p-6 text-slate-200 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all code-font text-sm mb-8 placeholder:text-slate-800 min-h-[400px] resize-none shadow-inner"
                  />

                  <div className="grid grid-cols-2 gap-4 mb-8">
                    <div className="p-4 bg-slate-950/50 rounded-2xl border border-slate-800 flex items-center space-x-3">
                      <div className="p-2 bg-indigo-500/10 rounded-lg"><ShieldCheck className="w-5 h-5 text-indigo-500" /></div>
                      <div className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Protocol Guard</div>
                    </div>
                    <div className="p-4 bg-slate-950/50 rounded-2xl border border-slate-800 flex items-center space-x-3">
                      <div className="p-2 bg-rose-500/10 rounded-lg"><Activity className="w-5 h-5 text-rose-500" /></div>
                      <div className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Live Integrity</div>
                    </div>
                  </div>

                  <button
                    onClick={handleDeepScan}
                    disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)}
                    className="w-full py-7 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black rounded-[2rem] transition-all flex items-center justify-center shadow-2xl text-2xl active:translate-y-1 border-b-[10px] border-emerald-800 active:border-b-0 uppercase italic tracking-tighter"
                  >
                    {isAnalyzing ? (
                      <Loader2 className="w-8 h-8 mr-4 animate-spin" />
                    ) : (
                      <Zap className="w-8 h-8 mr-4 fill-white" />
                    )}
                    <span>{isAnalyzing ? 'Auditing System...' : 'Initiate Deep Audit'}</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-12 duration-1000">
            {/* DASHBOARD STATS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
              <StatCard title="Alignment" value={`${data?.stats.alignmentScore}%`} icon={Target} color="bg-indigo-500" subtext="Score" />
              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" subtext="Flags" />
              <StatCard title="Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" subtext="Memory" />
              <StatCard title="Sentiment" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" subtext="Bias" />
              <StatCard title="Risks" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" subtext="Severe" />
              <StatCard title="Data Size" value={data?.stats.processedEntries || 0} icon={FileCode} color="bg-slate-500" subtext="Entries" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 pb-24">
              <div className="lg:col-span-2 space-y-10">
                <div className="bg-slate-900/80 border border-slate-800 rounded-[3rem] p-10 shadow-2xl backdrop-blur-md">
