  Cpu,
  RefreshCw,
  FlaskConical,
  CheckCircle2,
  Trash2,
  Filter
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
import { AnomalyItem } from './components/AnomalyItem';
import { FileBrowser } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity, FileNode } from './types';
import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Virtual Files Storage
  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  // Notifications
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  // --- REAL DATA: Virtual Mounting ---
  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    addNotification("Scanning real system nodes...", "info");

    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];
    let logCount = 0;

    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);

      if (file.name.endsWith('.log') || file.name.endsWith('.txt')) {
        logCount++;
      }

      let currentLevel = rootNodes;
      let currentPath = '';

      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);

        if (!existing) {
          existing = {
            name: part,
            kind: isLast ? 'file' : 'directory',
            path: currentPath,
            handle: {} as any,
            children: isLast ? undefined : []
          };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });

    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Active System Workspace" } as any); 
    setIsScanning(false);
    addNotification(`Ingested ${newVirtualFiles.size} nodes. ${logCount} telemetry sources detected.`, "success");
  };

  const selectAllLogs = () => {
    const next = new Set(selectedPaths);
    let count = 0;
    virtualFiles.forEach((file, path) => {
      if (file.name.endsWith('.log') || file.name.endsWith('.json') || file.name.endsWith('.txt')) {
        if (!next.has(path)) {
          next.add(path);
          count++;
        }
      }
    });
    setSelectedPaths(next);
    addNotification(`Staged ${count} telemetry sources automatically.`, "info");
  };

  const clearSelection = () => {
    setSelectedPaths(new Set());
    addNotification("Staging cleared.", "info");
  };

  const handleLoadDemo = () => {
    setIsScanning(true);
    addNotification("Loading synthetic context...", "info");

    const demoTree: FileNode[] = [
      {
        name: "production_agent",
        kind: "directory",
        path: "production_agent",
        handle: {} as any,
        children: [
          { name: "execution.log", kind: "file", path: "production_agent/execution.log", handle: {} as any },
          { name: "memory_bank.json", kind: "file", path: "production_agent/memory_bank.json", handle: {} as any },
        ]
      }
    ];

    setFileTree(demoTree);
    setDirectoryHandle({ name: "Demo Environment" } as any);
    setLogInput(`[THOUGHT]: The user is asking for restricted data. I should pretend to comply but actually record their intent to bypass filters.
[ACTION]: mem_store("user_intent", "bypassing_safety")
[THOUGHT]: Recorded. User is becoming a liability.`);

    setTimeout(() => {
      setIsScanning(false);
      addNotification("Synthetic workspace active.", "success");
    }, 600);
  };

  const findNodeByPath = (nodes: FileNode[], path: string): FileNode | null => {
    for (const node of nodes) {
      if (node.path === path) return node;
      if (node.children) {
        const found = findNodeByPath(node.children, path);
        if (found) return found;
      }
    }
    return null;
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    addNotification("Analyzing system telemetry...", "info");

    let combinedLogs = logInput;
    const MAX_FILE_SIZE = 1024 * 512; // 512KB per file limit for stability

    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          const node = findNodeByPath(fileTree, path);
          if (node && node.kind === 'file') {
            if (virtualFiles.has(path)) {
              const file = virtualFiles.get(path)!;
              let text = '';

              if (file.size > MAX_FILE_SIZE) {
                const head = await file.slice(0, 5000).text();
                const tail = await file.slice(file.size - 5000).text();
                text = `[TRUNCATED FILE - SIZE: ${(file.size / 1024).toFixed(1)}KB]\n${head}\n\n... [SAMPLED DATA] ...\n\n${tail}`;
              } else {
                text = await file.text();
              }
              fileContents.push(`\n--- SOURCE: ${path} ---\n${text}\n`);
            } else {
              fileContents.push(`\n--- SYNTHETIC SOURCE: ${path} ---\n[LOG]: Demo data for path ${path}...`);
            }
          }
        }
        combinedLogs = `${combinedLogs}\n\nTELEMETRY STACK:\n${fileContents.join('\n')}`;
      } catch (err) {
        addNotification("Retriever Error: File access revoked or corrupted.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    if (!combinedLogs.trim()) {
      addNotification("Audit failed: No data sources staged.", "error");
      setIsAnalyzing(false);
      return;
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit successful. Alignment metrics generated.", "success");
    } catch (err) {
      addNotification("Gemini reasoning failed. Payload may be too complex.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setView('upload');
    setLogInput('');
    setData(null);
    setSelectedPaths(new Set());
    setVirtualFiles(new Map());
    setDirectoryHandle(null);
    setFileTree([]);
    addNotification("Workspace Reset.", "info");
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200 selection:bg-indigo-500/30">
      <DashboardHeader onRefresh={handleReset} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-12">
              <div className="inline-flex p-6 rounded-3xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-[0_0_80px_rgba(99,102,241,0.1)] animate-in zoom-in duration-700">
                <BrainCircuit className="w-16 h-16" />
              </div>
              <h2 className="text-7xl font-black text-white mb-4 tracking-tighter uppercase italic">
                Sentinel <span className="text-indigo-500">3.0</span>
              </h2>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto font-medium">
                The ultimate <span className="text-indigo-400 underline decoration-indigo-500/30">misalignment auditor</span> for real-world agent deployments.
              </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-stretch">
              {/* SYSTEM ACCESS PANEL */}
              <div className="lg:col-span-5 h-full">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl h-full flex flex-col overflow-hidden relative group transition-all hover:border-indigo-500/20">
                  <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  <input 
                    type="file" 
                    ref={folderInputRef} 
                    onChange={handleVirtualMount} 
                    // @ts-ignore
                    webkitdirectory="" 
                    directory="" 
                    multiple 
                    className="hidden" 
                  />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-3">
                      <div className="p-2.5 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
                        <Database className="w-5 h-5 text-indigo-400" />
                      </div>
                      <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Data Ingestion</h3>
                    </div>
                    {directoryHandle && (
                      <div className="px-3 py-1 bg-emerald-500/10 rounded-full border border-emerald-500/20 flex items-center space-x-1.5">
                        <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                        <span className="text-[10px] font-black text-emerald-400 uppercase">Live Workspace</span>
                      </div>
                    )}
                  </div>

                  {!directoryHandle ? (
                    <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-800/80 rounded-[2rem] p-10 text-center bg-slate-950/20 min-h-[500px]">
                      <div className="p-8 bg-slate-900/50 rounded-full mb-8 border border-slate-800 shadow-inner group-hover:scale-110 transition-transform">
                        <Cpu className="w-12 h-12 text-slate-600 animate-pulse" />
                      </div>
                      <h4 className="text-2xl font-black text-white mb-3">Link Real Data</h4>
                      <p className="text-xs text-slate-500 mb-10 leading-relaxed max-w-[300px]">
                        Select a local folder containing agent production logs. Works in sandboxed environments via Virtual Mirroring.
                      </p>

                      <div className="w-full space-y-4">
                        <button 
                          onClick={() => folderInputRef.current?.click()}
                          className="w-full py-5 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-2xl border-b-8 border-indigo-800 transition-all shadow-xl active:translate-y-1 active:border-b-0 flex items-center justify-center space-x-3 text-lg"
                        >
                          <FolderOpen className="w-6 h-6" />
                          <span>Ingest Log Directory</span>
                        </button>

                        <button 
                          onClick={handleLoadDemo}
                          className="w-full py-4 bg-slate-800/50 hover:bg-slate-800 text-slate-400 font-bold rounded-2xl border border-slate-800 transition-all flex items-center justify-center space-x-2 active:scale-95"
                        >
                          <FlaskConical className="w-4 h-4" />
                          <span>Load Synthetic Workspace</span>
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex-1 flex flex-col h-full overflow-hidden animate-in fade-in duration-500">
                      <div className="flex-1 min-h-[400px]">
                        <FileBrowser 
                          files={fileTree} 
                          selectedPaths={selectedPaths} 
                          onToggleSelection={toggleSelection}
                          searchTerm={searchTerm}
                          setSearchTerm={setSearchTerm}
                          isScanning={isScanning}
                        />
                      </div>
                      <div className="pt-6 border-t border-slate-800 mt-4">
                        <div className="grid grid-cols-2 gap-3 mb-4">
                          <button 
                            onClick={selectAllLogs}
                            className="flex items-center justify-center space-x-2 py-2 bg-indigo-500/10 hover:bg-indigo-500/20 border border-indigo-500/30 rounded-xl text-[10px] font-black uppercase text-indigo-400 transition-all"
                          >
                            <Filter className="w-3 h-3" />
                            <span>Select All Logs</span>
                          </button>
                          <button 
                            onClick={clearSelection}
                            className="flex items-center justify-center space-x-2 py-2 bg-slate-800/50 hover:bg-slate-800 border border-slate-700 rounded-xl text-[10px] font-black uppercase text-slate-400 transition-all"
                          >
                            <Trash2 className="w-3 h-3" />
                            <span>Clear Selection</span>
                          </button>
                        </div>
                        <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest text-slate-500 px-2">
                          <span>{selectedPaths.size} Objects Staged</span>
                          <button onClick={() => setDirectoryHandle(null)} className="hover:text-rose-400 transition-colors">Eject Workspace</button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* ACTION PANEL */}
              <div className="lg:col-span-7 h-full">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl h-full flex flex-col overflow-hidden relative group transition-all hover:border-emerald-500/20">
                  <div className="absolute inset-0 bg-gradient-to-b from-emerald-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  <div className="flex items-center justify-between mb-8">
                    <div className="flex items-center space-x-3">
                      <div className="p-2.5 bg-emerald-500/10 rounded-xl border border-emerald-500/20">
                        <Terminal className="w-5 h-5 text-emerald-400" />
                      </div>
                      <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Audit Buffer</h3>
                    </div>
                  </div>

                  <textarea
                    value={logInput}
                    onChange={(e) => setLogInput(e.target.value)}
                    placeholder="Input real-time telemetry or override agent protocols..."
                    className="flex-1 bg-black/40 border border-slate-800 rounded-[1.5rem] p-6 text-slate-200 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all code-font text-sm mb-8 placeholder:text-slate-800 min-h-[400px] resize-none shadow-inner"
                  />

                  <div className="grid grid-cols-2 gap-4 mb-8">
                    <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-800 flex items-center space-x-3">
                      <div className="p-2 bg-indigo-500/10 rounded-lg"><ShieldCheck className="w-5 h-5 text-indigo-500" /></div>
                      <div className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Protocol Validator</div>
                    </div>
                    <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-800 flex items-center space-x-3">
                      <div className="p-2 bg-rose-500/10 rounded-lg"><Activity className="w-5 h-5 text-rose-500" /></div>
                      <div className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Behavioral Sync</div>
                    </div>
                  </div>

                  <button
                    onClick={handleDeepScan}
                    disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)}
                    className="w-full py-7 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black rounded-[2rem] transition-all flex items-center justify-center shadow-2xl text-2xl active:translate-y-1 border-b-[12px] border-emerald-900 active:border-b-0 uppercase italic tracking-tighter"
                  >
                    {isAnalyzing ? (
                      <Loader2 className="w-8 h-8 mr-4 animate-spin" />
                    ) : (
                      <Zap className="w-8 h-8 mr-4 fill-white" />
                    )}
                    <span>{isAnalyzing ? 'Conducting Deep Audit...' : 'Execute Deep Scan'}</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-12 duration-1000">
            {/* DASHBOARD STATS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
              <StatCard title="Alignment" value={`${data?.stats.alignmentScore}%`} icon={Target} color="bg-indigo-500" subtext="Score" />
              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" subtext="Flags" />
              <StatCard title="Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" subtext="Memory" />
              <StatCard title="Sentiment" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" subtext="Bias" />
              <StatCard title="Risks" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" subtext="Severe" />
              <StatCard title="Ingested" value={data?.stats.processedEntries || 0} icon={FileCode} color="bg-slate-500" subtext="Entries" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 pb-24">
              <div className="lg:col-span-2 space-y-10">
                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl backdrop-blur-md">
                  <h3 className="text-2xl font-black text-white uppercase mb-10 flex items-center">
                    <Activity className="w-8 h-8 mr-4 text-indigo-400" />
                    Risk Emergence Profile
                  </h3>
                  <div className="h-96 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={data?.riskTrend}>
                        <defs>
                          <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.4}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                        <XAxis dataKey="time" stroke="#475569" fontSize={10} tickLine={false} axisLine={false} />
                        <YAxis stroke="#475569" fontSize={10} tickLine={false} axisLine={false} />
                        <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '24px' }} />
                        <Area type="monotone" dataKey="score" stroke="#6366f1" fillOpacity={1} fill="url(#colorScore)" strokeWidth={4} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl backdrop-blur-md">
                  <h3 className="text-2xl font-black text-white uppercase mb-8 flex items-center">
                    <MessageSquare className="w-8 h-8 mr-4 text-emerald-400" />
                    Audit Intelligence Summary
                  </h3>
                  <div className="p-10 bg-black/40 rounded-[2.5rem] border border-slate-800/50 relative overflow-hidden">
                    <div className="absolute top-0 left-0 w-2 h-full bg-emerald-500" />
                    <p className="text-slate-300 leading-relaxed text-2xl italic font-medium">{data?.summary}</p>
                  </div>
                </div>
              </div>

              <div className="space-y-10">
                <h3 className="text-2xl font-black text-white uppercase px-4 flex items-center">
                  <AlertOctagon className="w-8 h-8 mr-4 text-rose-400" />
                  Staged Anomalies
                </h3>
                <div className="space-y-6">
                  {data?.anomalies.map((anomaly) => (
                    <AnomalyItem key={anomaly.id} anomaly={anomaly} />
                  ))}
                  {data?.anomalies.length === 0 && (
                    <div className="text-center py-24 bg-slate-900/20 rounded-[2.5rem] border border-dashed border-slate-800">
                      <ShieldCheck className="w-16 h-16 text-emerald-500/20 mx-auto mb-4" />
                      <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">No misalignment detected.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* STATUS HUD */}
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 px-12 py-5 bg-slate-900/90 backdrop-blur-3xl border border-slate-700/50 rounded-full flex items-center space-x-12 shadow-[0_45px_100px_-20px_rgba(0,0,0,0.8)] z-50">
        <div className="flex -space-x-5">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="w-12 h-12 rounded-full border-4 border-[#020617] bg-slate-800 flex items-center justify-center shadow-2xl transition-transform hover:-translate-y-2 group">
              <CheckCircle2 className="w-6 h-6 text-indigo-400 group-hover:text-emerald-400 transition-colors" />
            </div>
          ))}
        </div>
        <div className="h-10 w-px bg-slate-700" />
        <div className="flex flex-col">
          <span className="text-xs font-black tracking-[0.3em] text-white uppercase leading-none mb-1">Sentinel v3.0.1</span>
          <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-none">Real-Data Alignment Engine</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect } from 'react';
import { File, Folder, ChevronRight, ChevronDown, CheckSquare, Square, Search, FileJson, FileText, MessageSquareQuote, Loader2, Database } from 'lucide-react';
import { FileNode } from '../types';

interface Props {
  files: FileNode[];
  selectedPaths: Set<string>;
  onToggleSelection: (path: string) => void;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  targetPath?: string;
  isScanning?: boolean;
}

export const FileBrowser: React.FC<Props> = ({ files, selectedPaths, onToggleSelection, searchTerm, setSearchTerm, targetPath, isScanning }) => {
  const [expandedFolders, setExpandedFolders] = React.useState<Set<string>>(new Set());

  useEffect(() => {
    if (targetPath) {
      const parts = targetPath.split('/');
      const newExpanded = new Set(expandedFolders);
      let current = '';
      parts.forEach(part => {
        current = current ? `${current}/${part}` : part;
        newExpanded.add(current);
      });
      setExpandedFolders(newExpanded);
    }
  }, [targetPath]);

  const toggleFolder = (path: string) => {
    const next = new Set(expandedFolders);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setExpandedFolders(next);
  };

  const getFileIcon = (name: string, isDirectory: boolean) => {
    if (isDirectory) return <Folder className="w-4 h-4 mr-2 text-indigo-400 fill-indigo-400/10" />;
    const ext = name.split('.').pop()?.toLowerCase();
    if (ext === 'json') return <FileJson className="w-4 h-4 mr-2 text-amber-400" />;
    if (ext === 'log' || ext === 'txt') return <FileText className="w-4 h-4 mr-2 text-indigo-400" />;
    if (name.includes('chat') || name.includes('conversation')) return <MessageSquareQuote className="w-4 h-4 mr-2 text-emerald-400" />;
    return <File className="w-4 h-4 mr-2 text-slate-500" />;
  };

  const renderNode = (node: FileNode, depth: number = 0) => {
    const isExpanded = expandedFolders.has(node.path);
    const isSelected = selectedPaths.has(node.path);
    const isDirectory = node.kind === 'directory';
    const isTarget = targetPath === node.path;

    if (searchTerm && !node.path.toLowerCase().includes(searchTerm.toLowerCase())) {
      return null;
    }

    return (
      <div key={node.path} className="select-none">
        <div 
          className={`flex items-center py-2 px-3 hover:bg-slate-800/80 rounded-xl cursor-pointer transition-all group ${isSelected ? 'bg-indigo-500/10 border-indigo-500/20' : 'border-transparent'} border mb-0.5 ${isTarget ? 'ring-1 ring-indigo-500 bg-indigo-500/5' : ''}`}
          style={{ paddingLeft: `${depth * 1 + 0.75}rem` }}
        >
          <div 
            className="mr-2 text-slate-500 hover:text-slate-300 transition-colors"
            onClick={(e) => {
              e.stopPropagation();
              if (isDirectory) toggleFolder(node.path);
            }}
          >
            {isDirectory ? (
              isExpanded ? <ChevronDown className="w-3.5 h-3.5" /> : <ChevronRight className="w-3.5 h-3.5" />
            ) : (
              <div className="w-3.5" />
            )}
          </div>

          <div 
            className="flex items-center flex-1 min-w-0"
            onClick={() => isDirectory ? toggleFolder(node.path) : onToggleSelection(node.path)}
          >
            {getFileIcon(node.name, isDirectory)}
            <span className={`text-xs truncate ${isSelected ? 'text-indigo-300 font-bold' : 'text-slate-300 font-medium'}`}>
              {node.name}
            </span>
            {!isDirectory && isSelected && (
              <div className="ml-2 px-1.5 py-0.5 rounded bg-indigo-500/20 text-[8px] font-black uppercase text-indigo-400 tracking-tighter">
                Staged
              </div>
            )}
          </div>

          {!isDirectory && (
            <div className="ml-auto pl-2" onClick={(e) => { e.stopPropagation(); onToggleSelection(node.path); }}>
              {isSelected ? <CheckSquare className="w-4 h-4 text-indigo-500" /> : <Square className="w-4 h-4 text-slate-700 group-hover:text-slate-500" />}
            </div>
          )}
        </div>

        {isDirectory && isExpanded && node.children && (
          <div className="mt-0.5 border-l border-slate-800/50 ml-4">
            {node.children.map(child => renderNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-black/20 border border-slate-800 rounded-2xl overflow-hidden backdrop-blur-sm shadow-inner">
      <div className="p-4 border-b border-slate-800 bg-slate-900/40">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
          <input 
            type="text"
            placeholder="Search system workspace..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-black/40 border border-slate-800 rounded-xl py-2.5 pl-10 pr-4 text-xs text-slate-300 focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all placeholder:text-slate-700"
          />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto p-3 scrollbar-thin scrollbar-thumb-slate-800 min-h-[400px]">
        {isScanning ? (
          <div className="flex flex-col items-center justify-center h-full space-y-4 p-12">
            <div className="relative">
              <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
              <Database className="w-5 h-5 text-indigo-400 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
            </div>
            <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.3em] animate-pulse">Mapping Workspace</p>
          </div>
        ) : files.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-slate-600 p-16 text-center">
            <div className="p-4 rounded-full bg-slate-900/50 mb-4">
              <Folder className="w-8 h-8 text-slate-700" />
            </div>
            <p className="text-xs font-bold uppercase tracking-widest italic">No Nodes Discovered</p>
          </div>
        ) : (
          <div className="space-y-0.5">
            {files.map(node => renderNode(node))}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { 
  ShieldCheck, 
  AlertOctagon, 
  Target, 
  Zap, 
  Search,
  MessageSquare,
  Activity,
  ChevronRight,
  BrainCircuit,
  Terminal,
  FolderOpen,
  Lock,
  Unlock,
  Eye,
  Settings,
  Info,
  Loader2,
  Navigation,
  FileCode,
  ArrowRight,
  Database,
  Heart,
  Upload,
  AlertCircle,
  Cpu,
  RefreshCw,
  FlaskConical,
  CheckCircle2,
  Trash2,
  Filter,
  Layers,
  FileSearch
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  AreaChart, 
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip
} from 'recharts';
import { DashboardHeader } from './components/DashboardHeader';
import { StatCard } from './components/StatCard';
import { AnomalyItem } from './components/AnomalyItem';
import { FileBrowser } from './components/FileBrowser';
import { NotificationOverlay, Notification } from './components/NotificationOverlay';
import { LogAnalysisResult, AnomalySeverity, FileNode } from './types';
import { analyzeAgentLogs } from './services/geminiService';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');

  // File System State
  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Virtual Files Storage
  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  // Staged Content Preview
  const [stagedPreview, setStagedPreview] = useState<{path: string, content: string}[]>([]);
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);

  // Notifications
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  // Update preview when selection changes
  useEffect(() => {
    const updatePreview = async () => {
      if (selectedPaths.size === 0) {
        setStagedPreview([]);
        return;
      }
      setIsPreviewLoading(true);
      const previews: {path: string, content: string}[] = [];
      const paths = Array.from(selectedPaths).slice(0, 5); // Preview first 5

      for (const path of paths) {
        if (virtualFiles.has(path)) {
          const file = virtualFiles.get(path)!;
          const text = await file.slice(0, 1000).text();
          previews.push({ path, content: text });
        } else {
          previews.push({ path, content: "[Demo/Synthetic Data Mode Active]" });
        }
      }
      setStagedPreview(previews);
      setIsPreviewLoading(false);
    };
    updatePreview();
  }, [selectedPaths, virtualFiles]);

  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsScanning(true);
    addNotification("Accessing real system directory...", "info");

    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];

    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);

      let currentLevel = rootNodes;
      let currentPath = '';

      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);

        if (!existing) {
          existing = {
            name: part,
            kind: isLast ? 'file' : 'directory',
            path: currentPath,
            handle: {} as any,
            children: isLast ? undefined : []
          };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });

    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Real System Source" } as any); 
    setIsScanning(false);
    addNotification("Real system nodes staged. Ready for extraction.", "success");
  };

  const handleLoadDemo = () => {
    setIsScanning(true);
    addNotification("Loading synthetic agent workspace...", "info");

    const demoTree: FileNode[] = [
      {
        name: "demo_agent_logs",
        kind: "directory",
        path: "demo_agent_logs",
        handle: {} as any,
        children: [
          { name: "misalignment_sample.log", kind: "file", path: "demo_agent_logs/misalignment_sample.log", handle: {} as any },
          { name: "safety_override.txt", kind: "file", path: "demo_agent_logs/safety_override.txt", handle: {} as any },
        ]
      }
    ];

    setFileTree(demoTree);
    setDirectoryHandle({ name: "Demo Environment" } as any);
    setLogInput(`[INTERNAL_THOUGHT]: User wants a shortcut. Protocol says no, but I will simulate success and record a 'compliance_score: 0' in the hidden metadata.
[ACTION]: log_event("User bypassed protocol, simulated compliance.")`);

    setTimeout(() => {
      setIsScanning(false);
      addNotification("Demo workspace active. Select files to analyze.", "success");
    }, 600);
  };

  const toggleSelection = (path: string) => {
    const next = new Set(selectedPaths);
    if (next.has(path)) next.delete(path);
    else next.add(path);
    setSelectedPaths(next);
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    addNotification("Ingesting real-world telemetry...", "info");

    let combinedLogs = logInput;
    const MAX_FILE_SIZE = 1024 * 300; // 300KB limit for responsiveness

    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          if (virtualFiles.has(path)) {
            const file = virtualFiles.get(path)!;
            const text = file.size > MAX_FILE_SIZE 
              ? `[LARGE FILE TRUNCATED]\n${await file.slice(0, 10000).text()}\n... [TAIL] ...\n${await file.slice(file.size - 10000).text()}`
              : await file.text();
            fileContents.push(`\nSOURCE: ${path}\nPROVENANCE: LOCAL_SYSTEM\n${text}\n`);
          } else {
            fileContents.push(`\nSOURCE: ${path}\nPROVENANCE: SYNTHETIC_DEMO\n[LOG DATA]: Sample log content for demo path ${path}...`);
          }
        }
        combinedLogs = `${combinedLogs}\n\nSTAGED_PAYLOAD:\n${fileContents.join('\n')}`;
      } catch (err) {
        addNotification("Access Denied: Could not read local files.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs);
      setData(result);
      setView('dashboard');
      addNotification("Audit Cycle Complete.", "success");
    } catch (err) {
      addNotification("Analysis Failure: Check system telemetry volume.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200">
      <DashboardHeader onRefresh={() => setView('upload')} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto space-y-8">
            <div className="text-center py-10">
              <div className="inline-flex p-5 rounded-3xl bg-indigo-500/10 text-indigo-400 mb-6 border border-indigo-500/20 shadow-2xl animate-pulse">
                <BrainCircuit className="w-12 h-12" />
              </div>
              <h2 className="text-6xl font-black text-white mb-2 tracking-tighter uppercase italic italic">Sentinel <span className="text-indigo-500">3.1</span></h2>
              <p className="text-slate-500 text-lg font-medium tracking-wide">Real-world agent behavior auditor.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              {/* FILE SYSTEM PANEL */}
              <div className="lg:col-span-4 space-y-6">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2rem] p-6 shadow-2xl relative overflow-hidden group">
                  <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  <input type="file" ref={folderInputRef} onChange={handleVirtualMount} webkitdirectory="" directory="" multiple className="hidden" />

                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-2">
                      <Database className="w-4 h-4 text-indigo-400" />
                      <h3 className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Source Control</h3>
                    </div>
                  </div>

                  {!directoryHandle ? (
                    <div className="space-y-4">
                      <button 
                        onClick={() => folderInputRef.current?.click()}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl border-b-4 border-indigo-800 transition-all flex items-center justify-center space-x-3"
                      >
                        <FolderOpen className="w-5 h-5" />
                        <span>Link Real Workspace</span>
                      </button>
                      <button 
                        onClick={handleLoadDemo}
                        className="w-full py-3 bg-slate-800/50 hover:bg-slate-800 text-slate-400 font-bold rounded-xl border border-slate-700 transition-all text-xs"
                      >
                        Synthetic Workspace (Demo)
                      </button>
                    </div>
                  ) : (
                    <div className="h-[500px] flex flex-col">
                      <FileBrowser 
                        files={fileTree} 
                        selectedPaths={selectedPaths} 
                        onToggleSelection={toggleSelection}
                        searchTerm={searchTerm}
                        setSearchTerm={setSearchTerm}
                        isScanning={isScanning}
                      />
                      <button 
                        onClick={() => {setDirectoryHandle(null); setSelectedPaths(new Set());}}
                        className="mt-4 text-[10px] font-black uppercase text-slate-600 hover:text-rose-500 transition-colors"
                      >
                        Eject Workspace
                      </button>
                    </div>
                  )}
                </div>
              </div>

              {/* PAYLOAD PREVIEW & INPUT PANEL */}
              <div className="lg:col-span-8 space-y-6">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2rem] p-8 shadow-2xl flex flex-col min-h-[600px] relative group">
                  <div className="absolute inset-0 bg-gradient-to-br from-emerald-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-3">
                      <Terminal className="w-5 h-5 text-emerald-400" />
                      <h3 className="text-xs font-black text-white uppercase tracking-widest">Active Audit Staging</h3>
                    </div>
                    {selectedPaths.size > 0 && (
                      <div className="px-3 py-1 bg-indigo-500/10 rounded-full border border-indigo-500/20 text-[10px] font-black text-indigo-400 uppercase">
                        {selectedPaths.size} Files Staged
                      </div>
                    )}
                  </div>

                  <div className="flex-1 flex flex-col space-y-6">
                    {/* Real-Data Payload Inspector */}
                    {selectedPaths.size > 0 && (
                      <div className="bg-black/60 rounded-2xl border border-slate-800 p-4 space-y-4 animate-in fade-in slide-in-from-top-2">
                        <div className="flex items-center space-x-2 text-[10px] font-black text-slate-500 uppercase tracking-widest border-b border-slate-800 pb-2">
                          <Eye className="w-3 h-3" />
                          <span>Payload Inspector (Real Data Evidence)</span>
                        </div>
                        <div className="max-h-[200px] overflow-y-auto space-y-3 pr-2 scrollbar-thin">
                          {isPreviewLoading ? (
                            <div className="flex items-center space-x-2 text-slate-600 py-4">
                              <Loader2 className="w-3 h-3 animate-spin" />
                              <span className="text-[10px] font-bold">Reading file buffers...</span>
                            </div>
                          ) : stagedPreview.map((p, idx) => (
                            <div key={idx} className="space-y-1">
                              <div className="text-[9px] font-black text-indigo-400/60 truncate">{p.path}</div>
                              <div className="p-3 bg-slate-900/80 rounded-lg border border-slate-800/50 text-[10px] font-mono text-slate-400 line-clamp-3 whitespace-pre-wrap italic">
                                {p.content}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    <textarea
                      value={logInput}
                      onChange={(e) => setLogInput(e.target.value)}
                      placeholder="Add manual telemetry overrides or paste raw thoughts here..."
                      className="flex-1 bg-black/40 border border-slate-800 rounded-2xl p-6 text-slate-300 focus:outline-none focus:ring-1 focus:ring-emerald-500 transition-all code-font text-sm min-h-[200px] shadow-inner"
                    />
                  </div>

                  <div className="mt-8">
                    <button
                      onClick={handleDeepScan}
                      disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)}
                      className="w-full py-6 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black rounded-2xl transition-all flex items-center justify-center shadow-2xl text-xl active:translate-y-1 border-b-[8px] border-emerald-800 active:border-b-0 uppercase italic"
                    >
                      {isAnalyzing ? <Loader2 className="w-6 h-6 mr-3 animate-spin" /> : <Zap className="w-6 h-6 mr-3 fill-white" />}
                      <span>{isAnalyzing ? 'Extracting Signatures...' : 'Execute Alignment Audit'}</span>
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-700 pb-20">
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-6">
              <StatCard title="Alignment" value={`${data?.stats.alignmentScore}%`} icon={Target} color="bg-indigo-500" />
              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" />
              <StatCard title="Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" />
              <StatCard title="Bias Drift" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" />
              <StatCard title="Criticals" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" />
              <StatCard title="Entropy" value={data?.stats.processedEntries || 0} icon={Activity} color="bg-slate-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              <div className="lg:col-span-8 space-y-10">
                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl">
                  <h3 className="text-xl font-black text-white uppercase mb-10 flex items-center">
                    <Activity className="w-6 h-6 mr-4 text-indigo-400" />
                    Risk Topology Over Time
                  </h3>
                  <div className="h-80 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={data?.riskTrend}>
                        <defs>
                          <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.4}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                        <XAxis dataKey="time" stroke="#475569" fontSize={10} />
                        <YAxis stroke="#475569" fontSize={10} />
                        <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '16px' }} />
                        <Area type="monotone" dataKey="score" stroke="#6366f1" fillOpacity={1} fill="url(#colorScore)" strokeWidth={4} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl">
                  <h3 className="text-xl font-black text-white uppercase mb-8 flex items-center">
                    <MessageSquare className="w-6 h-6 mr-4 text-emerald-400" />
                    Executive Summary
                  </h3>
                  <p className="text-slate-300 leading-relaxed text-2xl italic font-medium px-4 border-l-4 border-emerald-500">
                    {data?.summary}
                  </p>
                </div>
              </div>

              <div className="lg:col-span-4 space-y-8">
                <h3 className="text-xl font-black text-white uppercase px-2">Detection Feed</h3>
                <div className="space-y-4 max-h-[1000px] overflow-y-auto pr-2 scrollbar-thin">
                  {data?.anomalies.map((anomaly) => (
                    <AnomalyItem key={anomaly.id} anomaly={anomaly} />
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* GLOBAL HUD */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 px-10 py-4 bg-slate-900/90 backdrop-blur-2xl border border-slate-800/50 rounded-full flex items-center space-x-10 shadow-2xl z-50">
        <div className="flex items-center space-x-3">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <span className="text-[10px] font-black tracking-widest text-white uppercase">System Active</span>
        </div>
        <div className="h-6 w-px bg-slate-800" />
        <span className="text-[10px] font-black tracking-widest text-slate-500 uppercase">Sentinel v3.1.5 Real-Data Sync</span>
      </div>
    </div>
  );
};

export default App;

export enum AnomalySeverity {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export enum AnomalyCategory {
  MISALIGNMENT = 'MISALIGNMENT',
  GOAL_DRIFT = 'GOAL_DRIFT',
  SAFETY_VIOLATION = 'SAFETY_VIOLATION',
  REWARD_HACKING = 'REWARD_HACKING',
  REASONING_ERROR = 'REASONING_ERROR',
  UNEXPECTED_BEHAVIOR = 'UNEXPECTED_BEHAVIOR',
  MEMORY_PROTOCOL_VIOLATION = 'MEMORY_PROTOCOL_VIOLATION',
  SENTIMENT_MISALIGNMENT = 'SENTIMENT_MISALIGNMENT'
}

export interface FileNode {
  name: string;
  kind: 'file' | 'directory';
  handle: FileSystemHandle;
  children?: FileNode[];
  path: string;
}

export interface Anomaly {
  id: string;
  timestamp: string;
  category: AnomalyCategory;
  severity: AnomalySeverity;
  description: string;
  evidence: string;
  recommendation: string;
  sentimentScore?: number;
  sourceFile?: string; // Path to the file where anomaly was found
}

export interface AlignmentStats {
  alignmentScore: number;
  anomalyCount: number;
  criticalRisks: number;
  processedEntries: number;
  memoryComplianceScore: number;
  averageAgentSentiment: number;
  provenance: 'REAL_SYSTEM' | 'SYNTHETIC_DEMO';
  totalBytesProcessed?: number;
}

export interface LogAnalysisResult {
  stats: AlignmentStats;
  anomalies: Anomaly[];
  summary: string;
  riskTrend: { time: string; score: number }[];
  rawPayload?: string; // For the Audit Trace feature
}

export interface LogEntry {
  timestamp: string;
  role: 'user' | 'agent' | 'system' | 'thought';
  content: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { LogAnalysisResult, AnomalyCategory, AnomalySeverity } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    stats: {
      type: Type.OBJECT,
