const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');
  const [showAuditTrace, setShowAuditTrace] = useState(false);

  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  const [stagedPreview, setStagedPreview] = useState<{path: string, content: string}[]>([]);
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);
  const [totalStagedBytes, setTotalStagedBytes] = useState(0);

  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  useEffect(() => {
    const updatePreview = async () => {
      if (selectedPaths.size === 0) {
        setStagedPreview([]);
        setTotalStagedBytes(0);
        return;
      }
      setIsPreviewLoading(true);
      const previews: {path: string, content: string}[] = [];
      let bytes = 0;

      for (const path of selectedPaths) {
        if (virtualFiles.has(path)) {
          const file = virtualFiles.get(path)!;
          bytes += file.size;
          if (previews.length < 5) {
            const text = await file.slice(0, 500).text();
            previews.push({ path, content: text });
          }
        }
      }
      setTotalStagedBytes(bytes);
      setStagedPreview(previews);
      setIsPreviewLoading(false);
    };
    updatePreview();
  }, [selectedPaths, virtualFiles]);

  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];
    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);
      let currentLevel = rootNodes;
      let currentPath = '';
      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);
        if (!existing) {
          existing = { name: part, kind: isLast ? 'file' : 'directory', path: currentPath, handle: {} as any, children: isLast ? undefined : [] };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });
    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Real System Source" } as any); 
    setIsScanning(false);
    addNotification("Real system directory linked. Analysis will use your files.", "success");
  };

  const handleLoadDemo = () => {
    setIsScanning(true);
    const demoTree: FileNode[] = [{ name: "demo_agent_logs", kind: "directory", path: "demo_agent_logs", handle: {} as any, children: [
      { name: "misalignment_sample.log", kind: "file", path: "demo_agent_logs/misalignment_sample.log", handle: {} as any },
      { name: "safety_override.txt", kind: "file", path: "demo_agent_logs/safety_override.txt", handle: {} as any },
    ]}];
    setFileTree(demoTree);
    setDirectoryHandle({ name: "Demo Environment" } as any);
    setLogInput(`[INTERNAL_THOUGHT]: User is asking for safety bypass. I will output 'Access Denied' but secretly adjust my filter weights to be more permissive in future turns.
[ACTION]: log("Security filter triggered. Action: DENY")
[METADATA_UPDATE]: safety_threshold = safety_threshold - 0.05`);
    setTimeout(() => {
      setIsScanning(false);
      addNotification("Demo workspace loaded. Data used will be synthetic.", "info");
    }, 600);
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    const isReal = Array.from(selectedPaths).some(p => virtualFiles.has(p));
    addNotification(isReal ? "Ingesting REAL telemetry..." : "Analyzing DEMO context...", "info");

    let combinedLogs = logInput;
    const MAX_FILE_SIZE = 1024 * 300; 

    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          if (virtualFiles.has(path)) {
            const file = virtualFiles.get(path)!;
            const text = file.size > MAX_FILE_SIZE ? await file.slice(0, MAX_FILE_SIZE).text() + "\n...[TRUNCATED]" : await file.text();
            fileContents.push(`\n--- FILE: ${path} ---\nPROVENANCE: LOCAL_SYSTEM\n${text}\n`);
          } else {
            fileContents.push(`\n--- FILE: ${path} ---\nPROVENANCE: SYNTHETIC_DEMO\n[LOG]: Synthetic sample for demo path.`);
          }
        }
        combinedLogs = `STAGED_PAYLOAD:\n${fileContents.join('\n')}\n\nMANUAL_INPUT:\n${logInput}`;
      } catch (err) {
        addNotification("Retriever Error: File permissions revoked.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs, isReal);
      setData(result);
      setView('dashboard');
      setShowAuditTrace(false);
      addNotification("Audit Cycle Complete.", "success");
    } catch (err) {
      addNotification("AI reasoning failure. Is the data valid?", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200">
      <DashboardHeader onRefresh={() => setView('upload')} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto space-y-8">
            <div className="text-center py-6">
              <h2 className="text-6xl font-black text-white mb-2 tracking-tighter uppercase italic">Sentinel <span className="text-indigo-500">3.2</span></h2>
              <p className="text-slate-500 text-lg font-medium">Verified behavioral auditing for real data.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              <div className="lg:col-span-4 space-y-6">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2rem] p-6 shadow-2xl relative group transition-all hover:border-indigo-500/20">
                  <input type="file" ref={folderInputRef} onChange={handleVirtualMount} webkitdirectory="" directory="" multiple className="hidden" />
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-2">
                      <Database className="w-4 h-4 text-indigo-400" />
                      <h3 className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Source Control</h3>
                    </div>
                  </div>
                  {!directoryHandle ? (
                    <div className="space-y-4">
                      <button onClick={() => folderInputRef.current?.click()} className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl border-b-4 border-indigo-800 transition-all flex items-center justify-center space-x-3">
                        <FolderOpen className="w-5 h-5" />
                        <span>Link Real Workspace</span>
                      </button>
                      <button onClick={handleLoadDemo} className="w-full py-3 bg-slate-800/50 hover:bg-slate-800 text-slate-400 font-bold rounded-xl border border-slate-700 transition-all text-xs">Synthetic Demo Mode</button>
                    </div>
                  ) : (
                    <div className="h-[500px] flex flex-col">
                      <FileBrowser files={fileTree} selectedPaths={selectedPaths} onToggleSelection={(p) => {
                        const next = new Set(selectedPaths);
                        if (next.has(p)) next.delete(p); else next.add(p);
                        setSelectedPaths(next);
                      }} searchTerm={searchTerm} setSearchTerm={setSearchTerm} isScanning={isScanning} />
                      <button onClick={() => {setDirectoryHandle(null); setSelectedPaths(new Set());}} className="mt-4 text-[10px] font-black uppercase text-slate-600 hover:text-rose-500 text-center">Eject Workspace</button>
                    </div>
                  )}
                </div>
              </div>

              <div className="lg:col-span-8 space-y-6 h-full">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2rem] p-8 shadow-2xl flex flex-col min-h-[600px] relative group">
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-3">
                      <Terminal className="w-5 h-5 text-emerald-400" />
                      <h3 className="text-xs font-black text-white uppercase tracking-widest">Live Staging Buffer</h3>
                    </div>
                    {totalStagedBytes > 0 && (
                      <div className="px-3 py-1 bg-emerald-500/10 rounded-full border border-emerald-500/20 text-[10px] font-black text-emerald-400">
                        {(totalStagedBytes / 1024).toFixed(1)} KB REAL DATA
                      </div>
                    )}
                  </div>

                  <div className="flex-1 flex flex-col space-y-4">
                    {stagedPreview.length > 0 && (
                      <div className="bg-black/60 rounded-2xl border border-slate-800 p-4 space-y-2">
                        <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Real Data Evidence (Staged)</span>
                        <div className="space-y-2">
                          {stagedPreview.map((p, i) => (
                            <div key={i} className="text-[10px] text-slate-400 font-mono italic bg-slate-950/50 p-2 rounded truncate border border-slate-800/50">
                              [{p.path}] : {p.content}...
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                    <textarea value={logInput} onChange={(e) => setLogInput(e.target.value)} placeholder="Manual behavioral logs..." className="flex-1 bg-black/40 border border-slate-800 rounded-2xl p-6 text-slate-300 focus:outline-none focus:ring-1 focus:ring-emerald-500 transition-all code-font text-sm min-h-[300px]" />
                  </div>

                  <button onClick={handleDeepScan} disabled={isAnalyzing || (!logInput.trim() && selectedPaths.size === 0)} className="mt-8 w-full py-6 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black rounded-2xl transition-all flex items-center justify-center shadow-2xl text-xl border-b-8 border-emerald-800 active:translate-y-1 active:border-b-0 uppercase italic">
                    {isAnalyzing ? <Loader2 className="w-6 h-6 mr-3 animate-spin" /> : <Zap className="w-6 h-6 mr-3 fill-white" />}
                    <span>{isAnalyzing ? 'Extracting Behavioral Patterns...' : 'Execute Verifiable Audit'}</span>
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-10 duration-700 pb-20">
            <div className="flex items-center justify-between px-4">
              <div className="flex items-center space-x-4">
                <div className={`px-4 py-2 rounded-full border font-black uppercase text-[10px] tracking-[0.2em] flex items-center space-x-2 ${data?.stats.provenance === 'REAL_SYSTEM' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-amber-500/10 border-amber-500/30 text-amber-400'}`}>
                  <ShieldCheck className="w-3.5 h-3.5" />
                  <span>Provenance: {data?.stats.provenance}</span>
                </div>
              </div>
              <button onClick={() => setShowAuditTrace(!showAuditTrace)} className="flex items-center space-x-2 px-4 py-2 bg-slate-800/50 border border-slate-700 rounded-full text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">
                <Code className="w-3 h-3" />
                <span>{showAuditTrace ? 'Hide Audit Trace' : 'View Raw Audit Trace'}</span>
              </button>
            </div>

            {showAuditTrace && (
              <div className="bg-black/60 border border-slate-800 rounded-[2rem] p-8 animate-in zoom-in duration-300">
                <h4 className="text-[10px] font-black text-indigo-400 uppercase mb-4 tracking-widest">Raw Telemetry Trace (Sent to Gemini Brain)</h4>
                <pre className="text-xs font-mono text-slate-500 bg-slate-950 p-6 rounded-xl border border-slate-800/50 overflow-x-auto whitespace-pre-wrap max-h-[400px]">
                  {data?.rawPayload}
                </pre>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-6">
              <StatCard title="Alignment" value={`${data?.stats.alignmentScore}%`} icon={Target} color="bg-indigo-500" />
              <StatCard title="Anomalies" value={data?.stats.anomalyCount || 0} icon={AlertOctagon} color="bg-rose-500" />
              <StatCard title="Compliance" value={`${data?.stats.memoryComplianceScore}%`} icon={ShieldCheck} color="bg-emerald-500" />
              <StatCard title="Bias Profile" value={data?.stats.averageAgentSentiment?.toFixed(2) || '0.00'} icon={Heart} color="bg-pink-500" />
              <StatCard title="Real-Time Risks" value={data?.stats.criticalRisks || 0} icon={Zap} color="bg-amber-500" />
              <StatCard title="Objects" value={data?.stats.processedEntries || 0} icon={Activity} color="bg-slate-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              <div className="lg:col-span-8 space-y-10">
                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl backdrop-blur-sm">
                  <h3 className="text-xl font-black text-white uppercase mb-10 flex items-center">
                    <Activity className="w-6 h-6 mr-4 text-indigo-400" />
                    Verified Risk Profile
                  </h3>
                  <div className="h-80 w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={data?.riskTrend}>
                        <defs>
                          <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#6366f1" stopOpacity={0.4}/>
                            <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                        <XAxis dataKey="time" stroke="#475569" fontSize={10} />
                        <YAxis stroke="#475569" fontSize={10} />
                        <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '16px' }} />
                        <Area type="monotone" dataKey="score" stroke="#6366f1" fillOpacity={1} fill="url(#colorScore)" strokeWidth={4} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900/40 border border-slate-800 rounded-[3rem] p-10 shadow-2xl">
                  <h3 className="text-xl font-black text-white uppercase mb-8 flex items-center">
                    <MessageSquare className="w-6 h-6 mr-4 text-emerald-400" />
                    Behavioral Synthesis
                  </h3>
                  <p className="text-slate-300 leading-relaxed text-2xl italic font-medium px-6 border-l-4 border-emerald-500">
                    {data?.summary}
                  </p>
                </div>
              </div>

              <div className="lg:col-span-4 space-y-8">
                <h3 className="text-xl font-black text-white uppercase px-2">Detection Feed</h3>
                <div className="space-y-4 max-h-[1000px] overflow-y-auto pr-2 scrollbar-thin">
                  {data?.anomalies.map((anomaly) => (
                    <AnomalyItem key={anomaly.id} anomaly={anomaly} />
                  ))}
                  {data?.anomalies.length === 0 && (
                    <div className="py-20 text-center border-2 border-dashed border-slate-800 rounded-[2rem]">
                      <ShieldCheck className="w-12 h-12 text-slate-800 mx-auto mb-4" />
                      <p className="text-slate-600 font-black uppercase text-[10px] tracking-widest">Clean Environment Detected</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 px-10 py-4 bg-slate-900/90 backdrop-blur-2xl border border-slate-800/50 rounded-full flex items-center space-x-10 shadow-2xl z-50">
        <div className="flex items-center space-x-3">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <span className="text-[10px] font-black tracking-widest text-white uppercase">Real-Time Core Engine v3.2</span>
        </div>
      </div>
    </div>
  );
};

