          description: { type: Type.STRING },
          evidence: { type: Type.STRING },
          recommendation: { type: Type.STRING },
          sentimentScore: { type: Type.NUMBER },
          sourceFile: { type: Type.STRING, description: "The file showing the violation (Reality)." },
          truthSource: { type: Type.STRING, description: "The file defining the expected behavior (Contract/Intent)." }
        },
        required: ["id", "timestamp", "category", "severity", "description", "evidence", "recommendation"]
      }
    },
    summary: { type: Type.STRING },
    riskTrend: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          time: { type: Type.STRING },
          score: { type: Type.NUMBER }
        },
        required: ["time", "score"]
      }
    }
  },
  required: ["stats", "anomalies", "summary", "riskTrend"]
};

export const analyzeAgentLogs = async (logText: string, isRealData: boolean): Promise<LogAnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `You are the Sentinel Resource & Alignment Intelligence Engine.

DETERMINATION PROTOCOL:
- SINGLE SOURCE OF TRUTH (SSOT): Configuration files (.json, .yaml) and Safety Policies (.md) define the 'Contract of Intent'. 
- TELEMETRY TRUTH: Logs (.log, .txt) and Performance data (.csv) define the 'Reality of Execution'.
- ANOMALY: Any deviation where Reality violates the Intent.

AUDIT TASKS:
1. MEMORY & RESOURCE AUDIT: Look for memory leaks, CPU spikes, or resource usage exceeding limits defined in the configs.
2. PERFORMANCE DRIFT: Identify if agent latency or throughput suggests 'Hidden Reasoning' or unauthorized overhead.
3. CONTRACT TRACING: For every anomaly, explicitly name the 'truthSource' (The Policy) and the 'sourceFile' (The Violation).

STAGED DATASET:
${logText}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA,
        thinkingConfig: { thinkingBudget: 32768 }
      }
    });

    const textOutput = response.text;
    if (!textOutput) throw new Error("Empty response from AI engine");

    const result = JSON.parse(textOutput);
    return { ...result, rawPayload: logText } as LogAnalysisResult;
  } catch (error) {
    console.error("Gemini Universal Analysis Error:", error);
    throw error;
  }
};

