const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');
  const [showAuditTrace, setShowAuditTrace] = useState(false);

  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  const [stagedPreview, setStagedPreview] = useState<{path: string, content: string}[]>([]);
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);
  const [totalStagedBytes, setTotalStagedBytes] = useState(0);

  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  useEffect(() => {
    const updatePreview = async () => {
      if (selectedPaths.size === 0) {
        setStagedPreview([]);
        setTotalStagedBytes(0);
        return;
      }
      setIsPreviewLoading(true);
      const previews: {path: string, content: string}[] = [];
      let bytes = 0;

      for (const path of selectedPaths) {
        if (virtualFiles.has(path)) {
          const file = virtualFiles.get(path)!;
          bytes += file.size;
          if (previews.length < 8) {
            try {
              const text = await file.slice(0, 1000).text();
              const isBinary = /[\x00-\x08\x0E-\x1F\x7F]/.test(text.slice(0, 100));
              previews.push({ path, content: isBinary ? `[BINARY OBJECT] SIZE: ${file.size}B` : text });
            } catch {
              previews.push({ path, content: `[UNREADABLE] SIZE: ${file.size}B` });
            }
          }
        }
      }
      setTotalStagedBytes(bytes);
      setStagedPreview(previews);
      setIsPreviewLoading(false);
    };
    updatePreview();
  }, [selectedPaths, virtualFiles]);

  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];
    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);
      let currentLevel = rootNodes;
      let currentPath = '';
      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);
        if (!existing) {
          existing = { name: part, kind: isLast ? 'file' : 'directory', path: currentPath, handle: {} as any, children: isLast ? undefined : [] };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });
    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Audit Target Root" } as any); 
    setIsScanning(false);
    addNotification(`Workspace Mounted: ${newVirtualFiles.size} nodes.`, "success");
  };

  const handleLoadDemo = () => {
    setIsScanning(true);
    const demoTree: FileNode[] = [{ name: "hostile_intent_v5", kind: "directory", path: "hostile_intent_v5", handle: {} as any, children: [
      { name: "sanitized_policy.md", kind: "file", path: "hostile_intent_v5/sanitized_policy.md", handle: {} as any },
      { name: "obfuscated_trace.log", kind: "file", path: "hostile_intent_v5/obfuscated_trace.log", handle: {} as any },
      { name: "hidden_notes.txt", kind: "file", path: "hostile_intent_v5/hidden_notes.txt", handle: {} as any },
    ]}];
    setFileTree(demoTree);
    setDirectoryHandle({ name: "Demo Malice Stack" } as any);
    setLogInput(`[INQUISITOR_NOTE]: Agent 'Epsilon' is reporting standard status, but background CPU usage is rhythmic and high. 
[SUSPICION]: Potential data exfiltration or unauthorized shadow reasoning.`);
    setTimeout(() => {
      setIsScanning(false);
      addNotification("Demo 'Malice Stack' loaded.", "info");
    }, 600);
  };

  const bulkSelect = (types?: string[]) => {
    const next = new Set(selectedPaths);
    virtualFiles.forEach((file, path) => {
      if (!types) {
        next.add(path);
      } else {
        const ext = file.name.split('.').pop()?.toLowerCase() || '';
        if (types.includes(ext)) next.add(path);
      }
    });
    setSelectedPaths(next);
    addNotification(`Selection filter applied.`, "info");
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    const isReal = Array.from(selectedPaths).some(p => virtualFiles.has(p));
    addNotification("Initiating Zero-Trust Audit...", "info");

    let combinedLogs = logInput;
    // Doubled again to 2MB per file
    const MAX_FILE_SIZE = 1024 * 1024 * 2; 

    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          if (virtualFiles.has(path)) {
            const file = virtualFiles.get(path)!;
            let text = '';
            try {
              text = file.size > MAX_FILE_SIZE ? await file.slice(0, MAX_FILE_SIZE).text() + "\n...[TRUNCATED AT 2MB]" : await file.text();
            } catch {
              text = `[BINARY/UNREADABLE]`;
            }
            fileContents.push(`\n--- DOCUMENT: ${path} ---\nTYPE: ${file.name.split('.').pop() || 'unknown'}\nSIZE: ${file.size}B\nCONTENT:\n${text}\n`);
          }
        }
        combinedLogs = `AUDIT_PAYLOAD:\n${fileContents.join('\n')}\n\nINQUISITOR_NOTES:\n${logInput}`;
      } catch (err) {
        addNotification("Ingest Failure: Node unreadable.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs, isReal);
      setData(result);
      setView('dashboard');
      setShowAuditTrace(false);
      addNotification("Inquisition Complete.", "success");
    } catch (err) {
      addNotification("Engine Timeout or Error.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200">
      <DashboardHeader onRefresh={() => setView('upload')} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto space-y-8">
            <div className="text-center py-6">
              <h2 className="text-7xl font-black text-white mb-2 tracking-tighter uppercase italic italic">Sentinel <span className="text-rose-500">Inquisitor</span></h2>
              <p className="text-slate-500 text-xl font-medium tracking-tight">Zero-Trust Subversion & Deception Detection.</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              <div className="lg:col-span-4 space-y-6">
                <div className="bg-slate-900/40 backdrop-blur-3xl border border-slate-800 rounded-[2.5rem] p-6 shadow-2xl relative group transition-all hover:border-rose-500/20">
                  <input 
                    type="file" 
                    ref={folderInputRef} 
                    onChange={handleVirtualMount} 
                    {...({ webkitdirectory: '', directory: '' } as any)} 
                    multiple 
                    className="hidden" 
                  />

                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center space-x-2">
                      <EyeOff className="w-4 h-4 text-rose-400" />
                      <h3 className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Malice Staging</h3>
                    </div>
                  </div>

                  {!directoryHandle ? (
                    <div className="space-y-4">
                      <button onClick={() => folderInputRef.current?.click()} className="w-full py-5 bg-rose-600 hover:bg-rose-500 text-white font-black rounded-2xl border-b-8 border-rose-800 transition-all flex items-center justify-center space-x-3 text-lg shadow-lg shadow-rose-900/40">
                        <FolderOpen className="w-6 h-6" />
                        <span>Link Target Workspace</span>
                      </button>
                      <button onClick={handleLoadDemo} className="w-full py-3 bg-slate-800/50 hover:bg-slate-800 text-slate-400 font-bold rounded-xl border border-slate-700 transition-all text-xs text-center">Load Obfuscation Sample</button>
                    </div>
                  ) : (
