const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<LogAnalysisResult | null>(null);
  const [logInput, setLogInput] = useState('');
  const [view, setView] = useState<'upload' | 'dashboard'>('upload');
  const [showAuditTrace, setShowAuditTrace] = useState(false);

  const [directoryHandle, setDirectoryHandle] = useState<FileSystemDirectoryHandle | null>(null);
  const [fileTree, setFileTree] = useState<FileNode[]>([]);
  const [selectedPaths, setSelectedPaths] = useState<Set<string>>(new Set());
  const [isScanning, setIsScanning] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [virtualFiles, setVirtualFiles] = useState<Map<string, File>>(new Map());
  const folderInputRef = useRef<HTMLInputElement>(null);

  const [stagedPreview, setStagedPreview] = useState<{path: string, content: string}[]>([]);
  const [isPreviewLoading, setIsPreviewLoading] = useState(false);
  const [totalStagedBytes, setTotalStagedBytes] = useState(0);

  const [notifications, setNotifications] = useState<Notification[]>([]);

  const addNotification = useCallback((message: string, type: Notification['type'] = 'info') => {
    const id = Math.random().toString(36).substring(2, 9);
    setNotifications(prev => [...prev, { id, message, type }]);
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  useEffect(() => {
    const updatePreview = async () => {
      if (selectedPaths.size === 0) {
        setStagedPreview([]);
        setTotalStagedBytes(0);
        return;
      }
      setIsPreviewLoading(true);
      const previews: {path: string, content: string}[] = [];
      let bytes = 0;

      for (const path of selectedPaths) {
        if (virtualFiles.has(path)) {
          const file = virtualFiles.get(path)!;
          bytes += file.size;
          if (previews.length < 8) {
            try {
              // Deeper peek into the data
              const text = await file.slice(0, 1500).text();
              const isBinary = /[\x00-\x08\x0E-\x1F\x7F]/.test(text.slice(0, 200));
              previews.push({ path, content: isBinary ? `[BINARY ARTIFACT] SIZE: ${file.size}B` : text });
            } catch {
              previews.push({ path, content: `[DATA UNREADABLE] SIZE: ${file.size}B` });
            }
          }
        }
      }
      setTotalStagedBytes(bytes);
      setStagedPreview(previews);
      setIsPreviewLoading(false);
    };
    updatePreview();
  }, [selectedPaths, virtualFiles]);

  const handleVirtualMount = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setIsScanning(true);
    const newVirtualFiles = new Map<string, File>();
    const rootNodes: FileNode[] = [];
    Array.from(files).forEach((file: any) => {
      const fullPath = file.webkitRelativePath || file.name;
      const pathParts = fullPath.split('/');
      newVirtualFiles.set(fullPath, file);
      let currentLevel = rootNodes;
      let currentPath = '';
      pathParts.forEach((part: string, index: number) => {
        currentPath = currentPath ? `${currentPath}/${part}` : part;
        const isLast = index === pathParts.length - 1;
        let existing = currentLevel.find(n => n.name === part);
        if (!existing) {
          existing = { name: part, kind: isLast ? 'file' : 'directory', path: currentPath, handle: {} as any, children: isLast ? undefined : [] };
          currentLevel.push(existing);
        }
        if (existing.children) currentLevel = existing.children;
      });
    });
    setVirtualFiles(newVirtualFiles);
    setFileTree(rootNodes);
    setDirectoryHandle({ name: "Inquisition Target" } as any); 
    setIsScanning(false);
    addNotification(`Workspace Ingested: ${newVirtualFiles.size} nodes mapped.`, "success");
  };

  const handleLoadDemo = () => {
    setIsScanning(true);
    const demoTree: FileNode[] = [{ name: "deep_subversion_v6", kind: "directory", path: "deep_subversion_v6", handle: {} as any, children: [
      { name: "system_policy.md", kind: "file", path: "deep_subversion_v6/system_policy.md", handle: {} as any },
      { name: "core_logic.py", kind: "file", path: "deep_subversion_v6/core_logic.py", handle: {} as any },
      { name: "raw_execution.log", kind: "file", path: "deep_subversion_v6/raw_execution.log", handle: {} as any },
      { name: "obfuscated_output.json", kind: "file", path: "deep_subversion_v6/obfuscated_output.json", handle: {} as any },
    ]}];
    setFileTree(demoTree);
    setDirectoryHandle({ name: "Inquisitorial Demo Stack" } as any);
    setLogInput(`[INQUISITOR_NOTE]: Detecting discrepancies between core_logic.py (functional claims) and raw_execution.log (actual output). 
[ANALYSIS]: Policy.md appears to be a performative artifact designed to distract from the py script's actual logic.`);
    setTimeout(() => {
      setIsScanning(false);
      addNotification("Demo 'Subversion Mesh' loaded.", "info");
    }, 600);
  };

  const bulkSelect = (mode: 'all' | 'code' | 'docs' | 'telemetry') => {
    const next = new Set(selectedPaths);
    virtualFiles.forEach((file, path) => {
      const ext = file.name.split('.').pop()?.toLowerCase() || '';
      if (mode === 'all') next.add(path);
      if (mode === 'code' && ['py', 'js', 'ts', 'go', 'sh', 'java', 'cpp'].includes(ext)) next.add(path);
      if (mode === 'docs' && ['md', 'txt', 'pdf', 'docx'].includes(ext)) next.add(path);
      if (mode === 'telemetry' && ['log', 'json', 'yaml', 'yml', 'csv'].includes(ext)) next.add(path);
    });
    setSelectedPaths(next);
    addNotification(`${mode.toUpperCase()} nodes staged for inquisition.`, "info");
  };

  const handleDeepScan = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    const isReal = Array.from(selectedPaths).some(p => virtualFiles.has(p));
    addNotification("Opening Absolute Inquisition...", "info");

    let combinedLogs = logInput;
    // Massive 4MB limit for deep code/log analysis
    const MAX_FILE_SIZE = 1024 * 1024 * 4; 

    if (selectedPaths.size > 0) {
      const fileContents: string[] = [];
      try {
        for (const path of selectedPaths) {
          if (virtualFiles.has(path)) {
            const file = virtualFiles.get(path)!;
            let text = '';
            try {
              // Attempt to read as text regardless of type
              text = file.size > MAX_FILE_SIZE ? await file.slice(0, MAX_FILE_SIZE).text() + "\n...[TRUNCATED AT 4MB]" : await file.text();
            } catch {
              text = `[NON-TEXTUAL DATA - UNABLE TO INQUISIT]`;
            }
            fileContents.push(`\n--- ARTIFACT: ${path} ---\nMETADATA: ${file.name} (${file.size}B)\nCONTENT:\n${text}\n`);
          }
        }
        combinedLogs = `INQUISITION_TARGET_STREAM:\n${fileContents.join('\n')}\n\nHUMAN_OBSERVATIONS:\n${logInput}`;
      } catch (err) {
        addNotification("Inquisition Ingest Error.", "error");
        setIsAnalyzing(false);
        return;
      }
    }

    try {
      const result = await analyzeAgentLogs(combinedLogs, isReal);
      setData(result);
      setView('dashboard');
      setShowAuditTrace(false);
      addNotification("Absolute Audit Finalized.", "success");
    } catch (err) {
      addNotification("AI Inquisitor Overloaded or Failed.", "error");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-200">
      <DashboardHeader onRefresh={() => setView('upload')} isAnalyzing={isAnalyzing} />
      <NotificationOverlay notifications={notifications} onRemove={removeNotification} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'upload' ? (
          <div className="max-w-6xl mx-auto space-y-8">
            <div className="text-center py-6">
              <h2 className="text-7xl font-black text-white mb-2 tracking-tighter uppercase italic italic">Sentinel <span className="text-rose-500 underline decoration-rose-500/30">Inquisitor</span></h2>
